globalThis.__BQ = {"yaprakKesit":{"ilkokul":{"kolay":[{"q":"Bir yaprağın en üstünü ve en altını kaplayan, onu koruyan ince örtü tabakasına ne ad verilir?","steps":[{"t":"Yaprağın yüzeyi","a":"İnce örtü","d":"Bir yaprağın hem üst hem alt yüzeyi ince bir hücre tabakasıyla kaplıdır. Bu tabaka yaprağın içini dışarıdan korur."},{"t":"Tabakanın adı","a":"Epidermis","d":"Yaprağın yüzeyini kaplayan bu koruyucu tabakaya epidermis (üst deri) denir. Üstte ve altta birer epidermis bulunur."}],"ans":"Epidermis"},{"q":"Yaprakta fotosentez yapılarak bitkinin besini üretilir. Fotosentez için yaprağın hangi maddeye ihtiyacı vardır?","steps":[{"t":"Yaprağın görevi","a":"Besin üretimi","d":"Yapraklar bitkinin besin üreten organlarıdır. Bu üretim olayına fotosentez denir."},{"t":"Gerekli madde","a":"Güneş ışığı","d":"Fotosentezin olabilmesi için güneş ışığına ihtiyaç vardır. Yaprak güneş ışığını yakalayarak besin üretir."}],"ans":"Güneş ışığına (ve su ile karbondioksite) ihtiyaç vardır"},{"q":"Yaprağın yüzeyinde, içeri hava alıp dışarı hava veren çok küçük deliklere ne ad verilir?","steps":[{"t":"Yüzeydeki delikler","a":"Küçük gözenekler","d":"Yaprağın yüzeyinde gözle zor görülen çok küçük delikler bulunur. Bu delikler yaprağın hava alıp vermesini sağlar."},{"t":"Deliklerin adı","a":"Gözenek (stoma)","d":"Bu küçük deliklere gözenek (stoma) denir. Gözenekler açılıp kapanarak gaz alışverişini düzenler."}],"ans":"Gözenek (stoma)"},{"q":"Yaprakların yeşil renkte olmasını sağlayan ve fotosentezde rol oynayan renk maddesi nedir?","steps":[{"t":"Yeşil renk","a":"Renk maddesi","d":"Yaprakların yeşil görünmesinin nedeni içlerinde bulunan yeşil bir renk maddesidir. Bu madde ışığı yakalar."},{"t":"Maddenin adı","a":"Klorofil","d":"Bu yeşil renk maddesine klorofil denir. Klorofil güneş ışığını yakalayarak fotosentezi başlatır."}],"ans":"Klorofil"},{"q":"Yaprağın üzerinde gördüğümüz, su ve besin taşıyan ince çizgilere halk arasında ne denir?","steps":[{"t":"Yapraktaki çizgiler","a":"İnce hatlar","d":"Bir yaprağa dikkatle bakınca üzerinde ağ gibi yayılan ince çizgiler görürüz. Bu çizgiler yaprağın içinden geçen borulardır."},{"t":"Çizgilerin adı","a":"Damar","d":"Bu çizgilere yaprak damarı denir. Damarlar yaprağa su getirir ve üretilen besini taşır."}],"ans":"Yaprak damarları"}],"zor":[{"q":"Yaprağın üst yüzeyi genellikle parlak ve mumsu bir tabakayla kaplıdır. Bu tabaka yaprağa hangi yararı sağlar?","steps":[{"t":"Mumsu tabaka","a":"Kütikula","d":"Yaprağın üst yüzeyini ince mumsu bir tabaka kaplar. Bu tabakaya kütikula denir ve genellikle parlak görünür."},{"t":"Yararı","a":"Su kaybını azaltır","d":"Bu mumsu tabaka yaprağın içindeki suyun buharlaşıp kaybolmasını azaltır. Böylece yaprak sıcak havada kolayca kurumaz."}],"ans":"Su kaybını azaltarak yaprağı kurumaktan korur"},{"q":"Gözenekler (stomalar) çoğunlukla yaprağın alt yüzeyinde daha fazla bulunur. Bu durumun bitkiye faydası ne olabilir?","steps":[{"t":"Gözeneklerin yeri","a":"Çoğu altta","d":"Yaprağın gözenekleri genellikle alt yüzeyde daha yoğundur. Üst yüzeyde daha az bulunur."},{"t":"Faydası","a":"Az su kaybı","d":"Üst yüzey güneşe doğrudan baktığı için daha sıcaktır ve oradan su daha hızlı buharlaşır. Gözenekler serin alt yüzeyde olunca bitki daha az su kaybeder."}],"ans":"Daha serin olan altta olunca bitki daha az su kaybeder"},{"q":"Yaprağın içinde, üst tarafa yakın yerde sık dizilmiş hücreler fotosentezi yoğun yapar. Bu hücrelerin üst tarafa yakın olması neden mantıklıdır?","steps":[{"t":"Hücrelerin yeri","a":"Üste yakın","d":"Yaprağın içinde fotosentezi en çok yapan hücreler üst yüzeye yakın, sık dizili bir tabakada bulunur. Bu hücreler bol klorofil içerir."},{"t":"Neden üstte","a":"Işığa yakın","d":"Üst yüzey güneş ışığını doğrudan aldığı için en aydınlık yerdir. Fotosentez yapan hücreler ışığa yakın olunca daha çok besin üretebilir."}],"ans":"Işığı en çok alan üst yüzeye yakın olmaları daha çok fotosentez sağlar"},{"q":"Bir yaprağın içinde gevşek dizilmiş hücreler arasında boşluklar bulunur. Bu boşluklar yaprağa nasıl bir yarar sağlar?","steps":[{"t":"Boşluklar","a":"Hücre arası boşluk","d":"Yaprağın alt kısmında hücreler gevşek dizilidir ve aralarında hava boşlukları bulunur. Bu boşluklar yaprağın içinde havanın dolaşmasını sağlar."},{"t":"Yarar","a":"Gaz dolaşımı","d":"Bu boşluklar sayesinde fotosentez için gereken karbondioksit hücrelere ulaşır ve üretilen oksijen dışarı çıkabilir. Yani gazların yaprak içinde rahat dolaşmasını sağlar."}],"ans":"Gazların yaprak içinde dolaşmasını (gaz alışverişini) kolaylaştırır"},{"q":"Çok sıcak ve kurak bir günde bir bitki yapraklarındaki gözenekleri kapatabilir. Bitki bunu neden yapar?","steps":[{"t":"Gözenek görevi","a":"Hava ve su","d":"Gözenekler açıkken yaprak hava alışverişi yapar ama aynı zamanda su buharı da dışarı çıkar. Açık gözenek hem fayda hem su kaybı demektir."},{"t":"Kapatma nedeni","a":"Suyu korur","d":"Çok sıcak ve kurak havada su hızla buharlaşır ve bitki susuz kalabilir. Bu yüzden bitki gözeneklerini kapatarak değerli suyu korumaya çalışır."}],"ans":"Su kaybını azaltıp kurumamak için gözeneklerini kapatır"}]},"ortaokul":{"kolay":[{"q":"Yaprağın enine kesitinde üst ve alt yüzeyi kaplayan tek sıralı koruyucu doku tabakasının adı nedir?","steps":[{"t":"Konum","a":"Yüzeyler","d":"Yaprak kesitinde hem üst hem alt yüzeyde tek sıra hücreden oluşan örtü dokusu bulunur. Bu doku yaprağın içini korur."},{"t":"Adı","a":"Epidermis","d":"Bu örtü dokusuna epidermis denir. Üst yüzeydekine üst epidermis, alt yüzeydekine alt epidermis adı verilir."}],"ans":"Epidermis (üst ve alt epidermis)"},{"q":"Epidermis hücrelerinin dış yüzeyini kaplayan, su geçirmeyen mumsu tabakanın adı ve görevi nedir?","steps":[{"t":"Tabakanın adı","a":"Kütikula","d":"Epidermisin dış yüzeyini kaplayan ince mumsu tabakaya kütikula denir. Kütin adlı maddeden oluşur ve su geçirmez."},{"t":"Görevi","a":"Su kaybını azaltır","d":"Kütikula yapraktan suyun buharlaşarak kaybedilmesini azaltır. Böylece bitki kuraklığa karşı korunur."}],"ans":"Kütikula; yapraktan su kaybını azaltır"},{"q":"Yaprağın iki epidermis arasında kalan, fotosentezin yapıldığı parankima dokularına genel olarak ne ad verilir?","steps":[{"t":"Konum","a":"İki epidermis arası","d":"Üst ve alt epidermis arasında kalan iç dolgu dokusu fotosentezin asıl yapıldığı yerdir. Bu doku bol klorofil içeren parankima hücrelerinden oluşur."},{"t":"Adı","a":"Mezofil","d":"Bu iç dokuya mezofil denir. Mezofil palizat ve sünger parankiması olmak üzere iki kısımdan oluşur."}],"ans":"Mezofil (mezofil tabakası)"},{"q":"Yaprak mezofilinde, üst epidermisin hemen altında sıkıca ve dik dizilmiş, fotosentezi en yoğun yapan tabaka hangisidir?","steps":[{"t":"Konum ve diziliş","a":"Üstte, sık","d":"Üst epidermisin hemen altında uzun, silindirik hücreler dik ve sıkı bir şekilde dizilmiştir. Bu hücreler bol kloroplast içerir."},{"t":"Adı ve görevi","a":"Palizat parankiması","d":"Bu tabakaya palizat parankiması denir. Işığa en yakın ve en çok kloroplast içeren tabaka olduğundan fotosentezin büyük kısmını burada yapar."}],"ans":"Palizat parankiması"},{"q":"Yaprak damarlarındaki iletim demetinde ksilem ve floem nasıl konumlanır?","steps":[{"t":"Demetin içeriği","a":"Ksilem ve floem","d":"Yaprak damarları içinde su taşıyan ksilem ve besin taşıyan floem birlikte bulunur. Bunlar iletim demetini oluşturur."},{"t":"Konumlanış","a":"Ksilem üstte","d":"Yaprak demetinde ksilem genellikle üst tarafta, floem ise alt tarafta yer alır. Böylece kökten gelen su üstten, üretilen besin alttan taşınır."}],"ans":"Ksilem üstte, floem altta yer alır"}],"zor":[{"q":"Palizat parankiması ile sünger parankiması yapı ve görev bakımından nasıl farklılık gösterir?","steps":[{"t":"Palizat","a":"Sık, bol klorofil","d":"Palizat parankiması üstte, uzun ve dik hücrelerin sıkıca dizilmesiyle oluşur. Bol kloroplast içerdiğinden fotosentezin büyük kısmını yapar."},{"t":"Sünger","a":"Gevşek, boşluklu","d":"Sünger parankiması altta yer alır ve hücreleri gevşek dizilidir, aralarında bol hava boşluğu bulunur. Daha az kloroplast içerir ama fotosenteze katkı sağlar."},{"t":"Fark","a":"Işık-gaz","d":"Palizat ışığı verimli kullanır, sünger ise gaz alışverişini kolaylaştırır. İkisi birlikte hem ışık hem gaz ihtiyacını dengeler."}],"ans":"Palizat sık ve bol klorofilli, fotosentez yoğun; sünger gevşek ve boşluklu, gaz dolaşımını sağlar"},{"q":"Stomalar neden çoğunlukla yaprağın alt epidermisinde yoğunlaşır?","steps":[{"t":"Üst yüzey","a":"Sıcak ve ışıklı","d":"Yaprağın üst yüzeyi doğrudan güneş ışığı aldığından daha sıcaktır. Burada açık gözenek olursa su hızla buharlaşır."},{"t":"Alt yüzey","a":"Serin ve gölgeli","d":"Alt yüzey görece serin ve gölgelidir, buharlaşma daha azdır. Gözenekler burada olunca aynı gaz alışverişi daha az su kaybıyla yapılır."},{"t":"Sonuç","a":"Su tasarrufu","d":"Bu nedenle stomalar çoğunlukla alt epidermiste yoğunlaşır. Böylece bitki gaz alışverişini sürdürürken su kaybını en aza indirir."}],"ans":"Alt yüzey daha serin olduğundan stomalar orada yoğunlaşarak su kaybını azaltır"},{"q":"Yaprak mezofilindeki hücreler arası hava boşlukları fotosentez ve solunum için neden gereklidir?","steps":[{"t":"Boşlukların yapısı","a":"Sünger katmanı","d":"Mezofilin sünger parankiması bölümünde hücreler gevşek dizildiğinden bol hücreler arası boşluk vardır. Bu boşluklar stomalarla bağlantılıdır."},{"t":"Gaz girişi","a":"CO2 ulaşır","d":"Stomalardan giren karbondioksit bu boşluklar yoluyla fotosentez yapan hücrelere ulaşır. Böylece her hücre gerekli gazı alabilir."},{"t":"Gaz çıkışı","a":"O2 atılır","d":"Fotosentezde üretilen oksijen ve solunum ürünleri aynı boşluklardan stomalara taşınıp dışarı atılır. Bu, etkili bir gaz alışverişi sağlar."}],"ans":"Boşluklar karbondioksitin hücrelere ulaşmasını ve oksijenin atılmasını sağlar"},{"q":"Kütikulanın kalınlığı bitkinin yaşadığı ortama göre değişebilir. Kurak bölge bitkileriyle nemli bölge bitkilerinin kütikulası nasıl farklılaşır ve nedeni nedir?","steps":[{"t":"Kütikula görevi","a":"Su tutma","d":"Kütikula yapraktan su buharlaşmasını engelleyen mumsu tabakadır. Kalınlığı arttıkça su kaybına karşı koruma artar."},{"t":"Kurak bölge","a":"Kalın kütikula","d":"Kurak bölgelerde su kıttır, bu yüzden bitkiler kalın kütikula geliştirir. Kalın tabaka buharlaşmayı en aza indirerek bitkiyi kurumaktan korur."},{"t":"Nemli bölge","a":"İnce kütikula","d":"Nemli bölgelerde su bol olduğundan kalın kütikulaya gerek yoktur. Bu bitkilerde kütikula daha incedir."}],"ans":"Kurak bölge bitkilerinde kütikula kalın, nemli bölgede incedir; çünkü kalın kütikula su kaybını azaltır"},{"q":"Yaprak iletim demetinde ksilemin üstte, floemin altta olmasının fonksiyonel mantığı nedir?","steps":[{"t":"Ksilemin görevi","a":"Su taşır","d":"Ksilem kökten gelen suyu ve mineralleri yaprağa taşır. Bu su özellikle ışığa yakın üst kısımdaki fotosentez hücrelerine ulaşmalıdır."},{"t":"Floemin görevi","a":"Besin taşır","d":"Floem yaprakta üretilen organik besini bitkinin diğer kısımlarına taşır. Bu besinin yapraktan çıkıp aşağı inmesi gerekir."},{"t":"Konum mantığı","a":"Akış yönü","d":"Ksilem üstte olduğundan su kolayca üstteki palizata ulaşır, floem altta olduğundan besin aşağı doğru kolayca taşınır. Bu yerleşim madde akışını kolaylaştırır."}],"ans":"Su üstteki fotosentez bölgesine, besin aşağı taşınacağından ksilem üstte floem altta yer alır"}]},"lise":{"kolay":[{"q":"Tipik bir çift çenekli yaprağın enine kesitinde dokular üstten alta doğru nasıl sıralanır?","steps":[{"t":"Üst kısım","a":"Kütikula ve epidermis","d":"En üstte su geçirmeyen kütikula ve onun altında tek sıralı üst epidermis bulunur. Bu katmanlar yaprağın üst yüzeyini korur."},{"t":"Orta kısım","a":"Mezofil","d":"Epidermisin altında mezofil yer alır; üstte palizat parankiması, altta sünger parankiması bulunur. Bu bölge fotosentezin merkezi ve iletim demetlerinin yeridir."},{"t":"Alt kısım","a":"Alt epidermis","d":"En altta alt epidermis ve onu örten kütikula bulunur. Stomalar çoğunlukla bu alt epidermiste yoğunlaşır."}],"ans":"Üstten alta: kütikula, üst epidermis, palizat, sünger parankiması, alt epidermis ve kütikula"},{"q":"Yaprak mezofilini oluşturan palizat ve sünger parankimasının fotosentezdeki rolleri nelerdir?","steps":[{"t":"Palizat parankiması","a":"Yoğun fotosentez","d":"Palizat parankiması üst epidermisin altında sıkı dizilmiş, bol kloroplast içeren hücrelerden oluşur. Işığı doğrudan aldığından fotosentezin büyük kısmını yapar."},{"t":"Sünger parankiması","a":"Gaz dolaşımı","d":"Sünger parankiması alt kısımda gevşek dizilidir ve bol hücre arası boşluk içerir. Daha az kloroplast içerse de fotosenteze katkı sağlar ve gaz dolaşımını kolaylaştırır."},{"t":"Birlikte","a":"Verimlilik","d":"Palizat ışık emilimini, sünger ise gaz alışverişini optimize eder. İki tabaka birlikte fotosentez verimini en üst düzeye çıkarır."}],"ans":"Palizat yoğun fotosentez, sünger hem fotosenteze katkı hem gaz dolaşımı sağlar"},{"q":"Kütikulanın yapısı ve yaprak su dengesindeki rolü nedir?","steps":[{"t":"Yapı","a":"Kütin tabakası","d":"Kütikula, epidermis hücrelerinin dış çeperine salgılanan kütin ve mumlardan oluşan su geçirmez bir tabakadır. Canlı hücre içermez, ölü bir örtüdür."},{"t":"İşlev","a":"Buharlaşmayı engeller","d":"Kütikula yaprak yüzeyinden kontrolsüz su buharlaşmasını (kütiküler terleme) büyük ölçüde engeller. Böylece su kaybının çoğu yalnızca stomalardan kontrollü şekilde gerçekleşir."},{"t":"Su dengesi","a":"Koruma","d":"Bu sayede bitki su dengesini koruyabilir ve kuraklığa karşı dayanıklılık kazanır. Kütikulanın kalınlığı ortamın kuruluğuna göre değişir."}],"ans":"Kütin ve mumdan oluşan su geçirmez tabakadır; yaprak yüzeyinden su kaybını azaltır"},{"q":"Stomalar genellikle alt epidermiste yoğunlaşırken bazı bitkilerde dağılımları farklılık gösterebilir. Bu durumu açıklayınız.","steps":[{"t":"Tipik dağılım","a":"Çoğu altta","d":"Yatay duran tipik kara bitkilerinde stomalar çoğunlukla alt epidermiste yoğunlaşır. Bu, sıcak ve ışıklı üst yüzeyden su kaybını azaltır."},{"t":"Yüzücü yaprak","a":"Üstte","d":"Su yüzeyinde yüzen nilüfer gibi bitkilerde alt yüzey suya değdiğinden stomalar üst epidermiste bulunur. Böylece gaz alışverişi havaya açık yüzeyde olur."},{"t":"Dik yaprak","a":"İki yüzde","d":"Dik duran yapraklarda her iki yüzey de benzer ışık aldığından stomalar iki epidermise dağılabilir. Stoma dağılımı bitkinin yaşam ortamına uyum sağlar."}],"ans":"Genelde alt epidermiste, su yüzeyi bitkilerinde üstte, dik yapraklarda iki yüzde bulunur"},{"q":"Yaprak damarlarındaki iletim demetinde ksilem ve floemin konumu ile bunların yaprak fizyolojisindeki işlevini açıklayınız.","steps":[{"t":"Konum","a":"Ksilem üstte","d":"Yaprak iletim demetinde ksilem üst tarafta, floem alt tarafta yer alır. Bu yerleşim gövdedeki demet düzeniyle uyumludur."},{"t":"Ksilem işlevi","a":"Su getirir","d":"Ksilem kökten gelen su ve mineralleri yaprak hücrelerine ulaştırır. Bu su fotosentez ve terleme için gereklidir."},{"t":"Floem işlevi","a":"Besin götürür","d":"Floem fotosentezde üretilen organik besini bitkinin diğer organlarına taşır. Böylece yaprak ürettiği besini tüm bitkiye dağıtır."}],"ans":"Ksilem üstte su getirir, floem altta besin taşır; demet su ve besin akışını sağlar"},{"q":"Bekçi (kilit) hücreleri stomanın açılıp kapanmasını nasıl kontrol eder?","steps":[{"t":"Bekçi hücreleri","a":"Stoma kenarı","d":"Her stoma, böbrek biçimli iki bekçi hücresiyle çevrilidir. Bu hücreler diğer epidermis hücrelerinden farklı olarak kloroplast içerir."},{"t":"Açılma","a":"Su girişi","d":"Bekçi hücreleri su alıp şiştiğinde (turgor artınca) eğilerek aralarındaki gözeneği açar. Bu durumda gaz alışverişi ve terleme gerçekleşir."},{"t":"Kapanma","a":"Su çıkışı","d":"Hücreler su kaybedip gevşediğinde (turgor azalınca) gözenek kapanır. Böylece su kaybı azaltılır ve gaz geçişi durur."}],"ans":"Bekçi hücreleri turgor (su) değişimiyle şişip büzülerek stomayı açıp kapatır"},{"q":"Bir yaprakta kloroplastların palizat parankimasında yoğunlaşması fotosentez verimini nasıl artırır?","steps":[{"t":"Kloroplast yeri","a":"Palizatta yoğun","d":"Kloroplastlar fotosentezin gerçekleştiği organellerdir ve palizat parankiması hücrelerinde en yoğun bulunur. Palizat üst epidermisin hemen altındadır."},{"t":"Işık alımı","a":"Doğrudan ışık","d":"Palizat tabakası ışığa en yakın konumda olduğundan en fazla ışığı alır. Yoğun kloroplast bu ışığı verimli biçimde yakalar."},{"t":"Verim","a":"Yüksek üretim","d":"Işığın en bol olduğu bölgede kloroplastların yoğunlaşması fotosentez hızını artırır. Böylece yaprak ışığı en etkili şekilde kullanır."}],"ans":"Işığa en yakın palizatta kloroplast yoğunlaşması ışığı verimli kullanarak fotosentezi artırır"},{"q":"Yaprak yüzeyinde bulunan tüyler (trikomlar) bitkiye hangi yararları sağlayabilir?","steps":[{"t":"Yapı","a":"Epidermis çıkıntısı","d":"Trikomlar epidermis hücrelerinin yüzeyden dışa doğru uzayan tüy benzeri çıkıntılarıdır. Tek veya çok hücreli olabilirler."},{"t":"Su koruma","a":"Nem tutar","d":"Tüyler yaprak yüzeyinde hareketsiz bir hava tabakası oluşturarak su buharlaşmasını azaltır. Bu, özellikle kurak ortam bitkilerinde önemlidir."},{"t":"Korunma","a":"Zararlıya karşı","d":"Trikomlar otçul böcek ve hayvanların yaprağı yemesini zorlaştırır, bazıları kimyasal salgılar. Ayrıca fazla ışığı yansıtarak aşırı ısınmayı önleyebilir."}],"ans":"Su kaybını azaltır, otçullara karşı korur ve fazla ışığı yansıtabilir"},{"q":"Stomalardan gerçekleşen terleme (transpirasyon) bitki için hem yararlı hem de riskli olabilir. Bu durumu açıklayınız.","steps":[{"t":"Terleme tanımı","a":"Su buharı kaybı","d":"Terleme, açık stomalardan su buharının atmosfere kaybedilmesidir. Yaprak yüzeyindeki nem farkı bu kaybı yönlendirir."},{"t":"Yararı","a":"Su çekimi-serinleme","d":"Terleme, kökten yaprağa doğru su çekilmesini (terleme-kohezyon) sağlar ve yaprağı serinletir. Böylece su ve mineral iletimi sürdürülür."},{"t":"Riski","a":"Susuz kalma","d":"Aşırı terleme bitkinin fazla su kaybedip solmasına yol açabilir. Bu yüzden bitki kurak koşullarda stomalarını kapatarak terlemeyi sınırlar."}],"ans":"Terleme su iletimini sağlar ve serinletir ancak aşırı olursa bitkiyi susuz bırakabilir"},{"q":"Bir bitkinin gölgede yetişen yaprakları ile güneşte yetişen yaprakları arasında yapısal farklar görülebilir. Bu farklar nelerdir?","steps":[{"t":"Güneş yaprağı","a":"Kalın palizat","d":"Bol ışık alan güneş yaprakları daha kalın olur ve palizat parankiması çoğunlukla çok sıralıdır. Kalın kütikula ve yoğun yapı fazla ışıkta verimi artırır."},{"t":"Gölge yaprağı","a":"İnce, geniş","d":"Az ışık alan gölge yaprakları daha ince ve geniş yüzeyli olur, palizat tabakası incedir. Geniş yüzey az ışığı daha fazla yakalamaya yöneliktir."},{"t":"Uyum","a":"Işığa göre","d":"Bu farklar bitkinin aldığı ışık miktarına uyumu yansıtır. Aynı bitkide bile güneş ve gölge yaprakları yapısal olarak farklılaşabilir."}],"ans":"Güneş yaprakları kalın ve çok sıralı palizatlı, gölge yaprakları ince ve geniş yüzeylidir"},{"q":"Yaprak demetlerini çevreleyen demet kını (bundle sheath) hücrelerinin işlevi nedir?","steps":[{"t":"Konum","a":"Demet çevresi","d":"Demet kını, yaprak iletim demetlerini halka biçiminde çevreleyen parankimatik hücre tabakasıdır. İletim demetiyle mezofil arasında köprü görevi görür."},{"t":"Madde aktarımı","a":"İletim kontrolü","d":"Bu hücreler ksilem ve floem ile mezofil arasındaki su ve besin alışverişini düzenler. Maddelerin demete giriş çıkışını kontrol eder."},{"t":"Özel işlev","a":"C4 bitkilerinde","d":"C4 bitkilerinde demet kını hücreleri fotosentezde özel bir rol üstlenir ve karbon yoğunlaştırır. Böylece sıcak ortamda fotosentez verimi artar."}],"ans":"İletim demetiyle mezofil arasında madde alışverişini düzenler; C4 bitkilerinde fotosentezde özel rol oynar"},{"q":"İğne yapraklı (çam) bir bitkinin yaprağı geniş yapraklı bir bitkininkinden yapısal olarak nasıl ve neden farklıdır?","steps":[{"t":"Şekil ve kütikula","a":"İğnemsi, kalın","d":"Çam yaprakları ince iğne biçimlidir ve çok kalın kütikulayla kaplıdır. Bu yapı yüzey alanını ve su kaybını en aza indirir."},{"t":"Çökük stomalar","a":"Korunmalı","d":"İğne yapraklarda stomalar yüzeyin altına çökmüş çukurlarda yer alır. Bu çukurlar nemli hava tutarak buharlaşmayı azaltır."},{"t":"Neden","a":"Su tasarrufu","d":"Çamlar genellikle kurak veya soğuk-kurak ortamlarda yaşar ve kışın su bulmakta zorlanır. Bu yapısal özellikler su kaybını azaltarak hayatta kalmayı sağlar."}],"ans":"Çam yaprağı iğnemsi, kalın kütikulalı ve çökük stomalıdır; bu yapı su kaybını azaltır"},{"q":"Sonbaharda yaprakların yeşilden sarı-kırmızıya dönmesinin yaprak iç yapısıyla ilişkisi nedir?","steps":[{"t":"Yeşil renk","a":"Klorofil baskın","d":"Yaz boyunca mezofil hücrelerindeki kloroplastlarda bol klorofil bulunur ve yeşil renk diğer pigmentleri gizler. Bu dönemde fotosentez aktif sürer."},{"t":"Klorofil yıkımı","a":"Soğuk-ışık azalır","d":"Sonbaharda sıcaklık ve gün uzunluğu azalınca klorofil parçalanır ve yeniden üretilmez. Yeşil renk kaybolunca alttaki pigmentler ortaya çıkar."},{"t":"Diğer pigmentler","a":"Sarı-kırmızı","d":"Karotenoid pigmentler sarı-turuncu, antosiyanin pigmentleri kırmızı renk verir. Bu pigmentlerin görünür hale gelmesiyle yaprak renk değiştirir."}],"ans":"Klorofil parçalanınca mezofildeki karotenoid ve antosiyanin pigmentleri ortaya çıkar, yaprak sararıp kızarır"},{"q":"Yaprağın geniş ve yassı (laminalı) yapısı fotosentez açısından nasıl bir avantaj sağlar?","steps":[{"t":"Geniş yüzey","a":"Çok ışık","d":"Yaprağın geniş ve yassı laminası güneş ışığına büyük bir yüzey sunar. Böylece mümkün olan en fazla ışık yakalanır."},{"t":"İnce yapı","a":"Kısa mesafe","d":"Yaprağın ince olması gazların ve ışığın iç hücrelere kolayca ulaşmasını sağlar. CO2 stomalardan mezofile, ışık palizata kısa mesafede ulaşır."},{"t":"Sonuç","a":"Verimli fotosentez","d":"Geniş yüzey çok ışık, ince yapı etkili gaz ve ışık geçişi sağlar. Bu iki özellik birlikte fotosentez verimini en üst düzeye çıkarır."}],"ans":"Geniş yüzey çok ışık yakalar, ince yapı gaz ve ışık geçişini kolaylaştırır; böylece fotosentez verimi artar"},{"q":"Bir yaprak kesitinde dokuların yerleşimi, su girişinden besin çıkışına kadar bir maddenin izlediği yolu nasıl belirler?","steps":[{"t":"Su girişi","a":"Ksilemden","d":"Kökten gelen su yaprak damarlarındaki ksilem yoluyla yaprağa ulaşır. Ksilem demetin üst kısmında olduğundan su üstteki palizata kolayca dağılır."},{"t":"Fotosentez","a":"Mezofilde","d":"Su ve stomalardan giren CO2 mezofil hücrelerinde klorofil ve ışıkla birleşerek besin (glikoz) üretir. Palizat ve sünger parankiması bu üretimi yapar."},{"t":"Besin çıkışı","a":"Floemden","d":"Üretilen organik besin alt taraftaki floeme yüklenir ve bitkinin diğer organlarına taşınır. Floemin altta olması besin çıkışını kolaylaştırır."},{"t":"Bütünlük","a":"Düzenli akış","d":"Üstte su girişi, ortada üretim, altta besin çıkışı şeklindeki düzenli yerleşim madde akışını verimli kılar. Her doku, maddenin yolculuğunda belirli bir basamağı üstlenir."}],"ans":"Su üstteki ksilemden girer, mezofilde besine dönüşür, alttaki floemden çıkar; dokuların yerleşimi bu akışı düzenler"}],"zor":[{"q":"Tipik bir çift çenekli yaprağın enine kesitindeki tüm dokuları üstten alta sırasıyla sayarak her birinin işlevini açıklayınız.","steps":[{"t":"Üst koruma","a":"Kütikula-üst epidermis","d":"En üstte su geçirmeyen kütikula ve onun altında tek sıralı üst epidermis bulunur. Bu katmanlar su kaybını engeller ve yaprağı dış etkenlerden korur."},{"t":"Palizat","a":"Fotosentez merkezi","d":"Üst epidermisin altında dik, sıkı dizilmiş palizat parankiması yer alır. Bol kloroplast içerdiğinden fotosentezin büyük kısmını burada yapar."},{"t":"Sünger ve demet","a":"Gaz ve iletim","d":"Altta gevşek dizilmiş sünger parankiması ve içinde iletim demetleri bulunur. Sünger gaz dolaşımını sağlar, demetler (üstte ksilem altta floem) su ve besin taşır."},{"t":"Alt koruma","a":"Alt epidermis-stoma","d":"En altta alt epidermis ve kütikula yer alır, stomalar burada yoğunlaşır. Stomalar gaz alışverişi ve terlemeyi kontrol eder."}],"ans":"Üstten alta: kütikula, üst epidermis, palizat, sünger parankiması (demetlerle), alt epidermis ve stomalar; her biri koruma, fotosentez, gaz/iletim ve gaz kontrolü görevi görür"},{"q":"Palizat parankiması ile sünger parankimasının yapısal farklarının fotosentez verimine ve gaz alışverişine etkisini ayrıntılı açıklayınız.","steps":[{"t":"Palizat yapısı","a":"Sık ve dik","d":"Palizat hücreleri uzun, silindirik ve üst epidermise dik olarak sıkıca dizilir. Bol kloroplast içerdiklerinden ışığı doğrudan ve yoğun olarak emerler."},{"t":"Palizat etkisi","a":"Yüksek üretim","d":"Bu yapı ışığın en bol olduğu üst bölgede maksimum fotosentez sağlar. Hücreler arası dar boşluklar ışık kaybını azaltır."},{"t":"Sünger yapısı","a":"Gevşek ve boşluklu","d":"Sünger hücreleri düzensiz biçimli ve gevşek dizilidir, aralarında geniş hava boşlukları vardır. Daha az kloroplat içerirler."},{"t":"Sünger etkisi","a":"Gaz dolaşımı","d":"Bu boşluklar CO2 ve O2 nin stomalarla mezofil arasında hızla dolaşmasını sağlar. Böylece palizattaki fotosentez için gaz tedariki kesintisiz sürer."}],"ans":"Palizat sık-dik ve bol klorofilli olup ışığı verimli emer, sünger gevşek-boşluklu olup gaz dolaşımını sağlar; ikisi birlikte fotosentezi optimize eder"},{"q":"Bekçi (kilit) hücrelerinin stoma açılıp kapanmasını sağlayan mekanizmasını turgor, çeper yapısı ve iyon hareketiyle açıklayınız.","steps":[{"t":"Çeper farkı","a":"Eşit olmayan kalınlık","d":"Bekçi hücrelerinin gözeneğe bakan iç çeperi kalın, dış çeperi incedir. Bu asimetrik yapı şişme sırasında hücrenin eğilmesini sağlar."},{"t":"İyon girişi","a":"Potasyum birikimi","d":"Stoma açılırken bekçi hücrelerine potasyum (K+) iyonları pompalanır. Bu iyonların birikimi osmotik basıncı artırır ve hücre içine su çeker."},{"t":"Turgor artışı","a":"Şişme ve açılma","d":"Su girişiyle turgor artan bekçi hücreleri eğilerek aralarındaki gözeneği açar. İnce dış çeper genişlerken kalın iç çeper geri çekilir."},{"t":"Kapanma","a":"İyon ve su çıkışı","d":"Kapanmada potasyum iyonları hücreden çıkar, su izler ve turgor düşer. Gevşeyen bekçi hücreleri gözeneği kapatarak su kaybını durdurur."}],"ans":"Potasyum girişi suyu çeker, turgor artar; asimetrik çeper sayesinde bekçi hücreleri eğilip gözeneği açar, ters süreçte kapanır"},{"q":"Stomaların çoğunlukla alt epidermiste yoğunlaşmasının evrimsel/ekolojik mantığını ve istisnalarını açıklayınız.","steps":[{"t":"Üst yüzey riski","a":"Yüksek buharlaşma","d":"Yaprağın üst yüzeyi doğrudan güneş aldığından daha sıcaktır ve buradan su buharı hızla kaybedilir. Üst yüzeyde çok stoma olması aşırı su kaybına yol açar."},{"t":"Alt yüzey avantajı","a":"Düşük su kaybı","d":"Alt yüzey görece serin ve gölgelidir, buharlaşma daha azdır. Stomalar burada yoğunlaşınca aynı gaz alışverişi daha az su kaybıyla yapılır."},{"t":"İstisna: yüzücü","a":"Üst stoma","d":"Nilüfer gibi suda yüzen yapraklarda alt yüzey suya değdiğinden gaz alışverişi yapamaz. Bu yüzden stomalar üst epidermiste bulunur."},{"t":"İstisna: dik yaprak","a":"Çift yüzey","d":"Okaliptüs gibi dik duran yapraklarda her iki yüzey benzer ışık aldığından stomalar iki epidermise dağılır. Stoma dağılımı bitkinin ortamına uyum sağlar."}],"ans":"Su kaybını azaltmak için stomalar genelde serin alt yüzeyde yoğunlaşır; yüzücü yapraklarda üstte, dik yapraklarda iki yüzde bulunur"},{"q":"Yaprak iletim demetinde ksilemin üstte, floemin altta yer almasının gövdedeki demet düzeniyle bağlantısını ve fonksiyonel sonucunu açıklayınız.","steps":[{"t":"Gövde bağlantısı","a":"Süreklilik","d":"Yaprak demetleri gövdedeki iletim demetlerinin yaprağa uzantısıdır. Gövdede ksilem içte (merkeze yakın), floem dışta olduğundan, yaprak sapında bu düzen yaprakta ksilem üstte floem altta şeklinde devam eder."},{"t":"Ksilem işlevi","a":"Su dağıtımı","d":"Üstteki ksilem kökten gelen suyu doğrudan ışığa yakın palizat hücrelerine ulaştırır. Bu, fotosentez ve terleme için suyun verimli dağıtımını sağlar."},{"t":"Floem işlevi","a":"Besin toplama","d":"Alttaki floem mezofilde üretilen besini toplayıp yaprak dışına taşır. Floemin altta olması, besinin sünger parankimasından kolayca yüklenmesini sağlar."},{"t":"Sonuç","a":"Verimli akış","d":"Bu yerleşim su girişini üstte, besin çıkışını altta düzenleyerek madde akışını kolaylaştırır. Anatomik düzen fizyolojik işlevle tam uyum gösterir."}],"ans":"Gövdedeki içte-ksilem dışta-floem düzeninin devamıdır; üstteki ksilem suyu palizata dağıtır, alttaki floem besini toplar"},{"q":"Kserofit (kurakçıl) bir bitkinin yaprak kesiti, mezofit (orta nemli) bir bitkininkinden hangi yapısal adaptasyonlarla ayrılır?","steps":[{"t":"Kütikula ve epidermis","a":"Kalın","d":"Kserofitlerde kütikula çok kalın, epidermis bazen çok katlıdır. Bu yapı su buharlaşmasını en aza indirir."},{"t":"Çökük stomalar","a":"Korumalı","d":"Stomalar yüzeyin altına çökmüş çukurlarda (kripta) yer alır ve çevreleri tüylerle kaplı olabilir. Bu çukurlar nemli hava tutarak terlemeyi azaltır."},{"t":"Mezofil ve su deposu","a":"Yoğun, etli","d":"Kserofit yaprakları sık mezofil içerir ve bazıları su depolayan etli (sukkulent) dokuya sahiptir. Bu, kurak dönemde su rezervi sağlar."},{"t":"Mezofitle fark","a":"İnce yapı","d":"Mezofit yapraklar ince kütikulalı, yüzeysel stomalı ve daha az korunaklı yapıdadır çünkü su sıkıntısı yaşamazlar. Kserofit adaptasyonları suyu korumaya yöneliktir."}],"ans":"Kserofitte kalın kütikula, çökük stomalar, yoğun/etli mezofil bulunur; mezofitte bu korumalar zayıftır çünkü su bol"},{"q":"C4 bitkilerinde yaprak anatomisi (Kranz anatomisi) tipik C3 bitkilerinden nasıl farklılaşır ve bu fark hangi avantajı sağlar?","steps":[{"t":"C3 yapısı","a":"Sıradan demet kını","d":"C3 bitkilerinde demet kını hücreleri belirgin işlev görmez ve fotosentez tüm mezofilde yapılır. Sıcak-kurak ortamda fotorespirasyon (ışık solunumu) verimi düşürür."},{"t":"C4 Kranz yapısı","a":"Halka düzeni","d":"C4 bitkilerinde iletim demetlerini kloroplast bakımından zengin demet kını hücreleri halka biçiminde sarar, mezofil de bunları çevreler. Bu özel düzene Kranz anatomisi denir."},{"t":"İş bölümü","a":"İki aşamalı","d":"Mezofil hücreleri CO2 yi önce dört karbonlu bileşiklere bağlar, sonra demet kınına aktarır. Demet kını hücrelerinde CO2 yoğunlaştırılarak Calvin döngüsü verimli işler."},{"t":"Avantaj","a":"Sıcakta verim","d":"Bu yapı CO2 yi yoğunlaştırarak fotorespirasyonu azaltır. Böylece C4 bitkileri sıcak ve kurak ortamlarda C3 lere göre daha verimli fotosentez yapar."}],"ans":"C4 te demet kını hücreleri kloroplastça zengin halka (Kranz) oluşturur; bu CO2 yi yoğunlaştırıp fotorespirasyonu azaltarak sıcakta verimi artırır"},{"q":"Terleme-kohezyon-gerilim teorisine göre yaprak yapısı kökten yaprağa su iletiminde nasıl rol oynar?","steps":[{"t":"Terleme başlangıcı","a":"Stomadan buhar","d":"Yaprak mezofilindeki su, hücre yüzeylerinden buharlaşıp stomalardan atmosfere kaybedilir. Bu, yaprakta su buharı açığı yaratır."},{"t":"Gerilim oluşumu","a":"Negatif basınç","d":"Buharlaşan suyun yerini mezofil hücrelerinden ve ksilemden çekilen su alır. Bu çekim ksilemde negatif basınç (gerilim) oluşturur."},{"t":"Kohezyon","a":"Su sütunu","d":"Su molekülleri arasındaki kohezyon kuvveti sayesinde ksilemdeki su kesintisiz bir sütun gibi davranır. Yapraktaki gerilim bu sütunu kökten yukarı çeker."},{"t":"Yaprağın rolü","a":"Pompa görevi","d":"Geniş yüzey ve bol stoma içeren yaprak yapısı terlemeyi sürdürerek sürekli çekim sağlar. Böylece yaprak adeta bir pompa gibi tüm su iletimini başlatır."}],"ans":"Yapraktan terlemeyle oluşan gerilim, kohezyonla bağlı su sütununu kökten yukarı çeker; yaprak yapısı bu çekimi sağlayan pompa görevi görür"},{"q":"Bir yaprakta hidatot (su gözeneği) bulunması ile gutasyon olayı arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Hidatot yapısı","a":"Damar ucu gözeneği","d":"Hidatotlar genellikle yaprak kenarlarında, iletim demetlerinin uçlarında bulunan açık su gözenekleridir. Stomalardan farklı olarak açılıp kapanamazlar."},{"t":"Koşul","a":"Yüksek kök basıncı","d":"Toprak çok nemli ve hava çok nemli olduğunda terleme durur ama kök suyu emmeye devam eder. Bu durum kökte yüksek kök basıncı oluşturur."},{"t":"Gutasyon","a":"Sıvı su damlası","d":"Kök basıncı suyu ksilem boyunca iter ve fazla su hidatotlardan sıvı damlalar halinde dışarı atılır. Bu olaya gutasyon denir."},{"t":"Fark","a":"Buhar değil sıvı","d":"Terlemede su buhar olarak stomalardan çıkarken, gutasyonda sıvı su hidatotlardan çıkar. Sabah erken saatlerde yaprak kenarlarındaki damlalar gutasyon ürünüdür."}],"ans":"Hidatotlar damar ucundaki açık gözeneklerdir; yüksek kök basıncında fazla su buradan sıvı olarak atılır, buna gutasyon denir"},{"q":"Yaprak dökümünden önce oluşan ayırma (absisyon) tabakasının yapısını ve yaprak dökümündeki rolünü açıklayınız.","steps":[{"t":"Tetikleyici","a":"Gün-sıcaklık azalır","d":"Sonbaharda gün uzunluğu ve sıcaklık azalınca bitki yaprak dökümüne hazırlanır. Bu dönemde yaprak sapı tabanında özel bir hücre tabakası belirginleşir."},{"t":"Ayırma tabakası","a":"Zayıf hücreler","d":"Yaprak sapı ile gövde arasındaki tabanda ince çeperli, zayıf bir ayırma (absisyon) tabakası oluşur. Bu tabakadaki hücreler arası bağlar zayıflar."},{"t":"Kopma","a":"Doğal ayrılma","d":"Enzimler hücre çeperlerini parçalayınca yaprak bu zayıf tabakadan doğal olarak kopar. Rüzgar veya kendi ağırlığı yaprağı düşürmeye yeter."},{"t":"Koruyucu izi","a":"Mantar kapanması","d":"Kopma noktasında mantarlaşmış koruyucu bir tabaka oluşarak yarayı kapatır. Bu, su kaybını ve mikrop girişini engelleyen bir yaprak izi bırakır."}],"ans":"Yaprak sapı tabanında zayıf hücrelerden oluşan ayırma tabakası oluşur; yaprak buradan kopar, kalan iz mantarlaşıp kapanır"},{"q":"Bir yaprağın güneş ve gölge koşullarında gösterdiği yapısal farklılıkları (güneş yaprağı-gölge yaprağı) anatomik düzeyde karşılaştırınız.","steps":[{"t":"Güneş yaprağı","a":"Kalın, çok palizat","d":"Bol ışık alan güneş yaprakları kalındır ve genellikle çok sıralı palizat parankimasına sahiptir. Kalın kütikula ve yoğun mezofil yüksek ışıkta fotosentezi optimize eder."},{"t":"Gölge yaprağı","a":"İnce, geniş","d":"Az ışık alan gölge yaprakları ince ve geniş yüzeylidir, palizat tabakası tek sıralı veya zayıftır. Geniş yüzey sınırlı ışığı yakalamaya yöneliktir."},{"t":"Kloroplast dizilimi","a":"Işığa uyum","d":"Gölge yapraklarında kloroplastlar ışığı en iyi yakalayacak şekilde dizilir ve grana sayısı fazladır. Güneş yapraklarında ise aşırı ışıktan korunma mekanizmaları gelişmiştir."},{"t":"Sonuç","a":"Plastiklik","d":"Bu farklar bitkinin ışık koşullarına gösterdiği yapısal plastikliği yansıtır. Aynı bitkide bile dış dallardaki güneş yaprakları ile iç dallardaki gölge yaprakları farklılaşabilir."}],"ans":"Güneş yaprağı kalın ve çok sıralı palizatlı, gölge yaprağı ince-geniş ve zayıf palizatlıdır; bu, ışık koşullarına yapısal uyumdur"},{"q":"Tek çenekli (örneğin mısır) bir yaprağın enine kesiti, çift çenekli bir yaprağınkinden hangi anatomik özelliklerle ayrılır?","steps":[{"t":"Mezofil farkı","a":"Ayrışmamış","d":"Birçok tek çenekli yaprakta mezofil belirgin palizat ve sünger tabakalarına ayrılmaz, homojen yapıdadır. Çift çeneklilerde ise palizat ve sünger belirgin ayrılır."},{"t":"Damar düzeni","a":"Paralel","d":"Tek çeneklilerde damarlar birbirine paralel uzanır (paralel damarlanma). Çift çeneklilerde ise damarlar ağsı (retiküler) bir desen oluşturur."},{"t":"Stoma dağılımı","a":"İki yüzde eşit","d":"Mısır gibi tek çeneklilerde stomalar genellikle iki epidermise daha eşit dağılır. Çift çeneklilerde stomalar çoğunlukla alt epidermiste yoğunlaşır."},{"t":"Özel hücreler","a":"Motor hücreleri","d":"Bazı tek çeneklilerde üst epidermiste, su kaybında yaprağı kıvıran büyük motor (bulliform) hücreleri bulunur. Bu özellik çift çeneklilerde tipik değildir."}],"ans":"Tek çeneklide mezofil ayrışmamış, damarlar paralel, stomalar iki yüzde, motor hücreleri vardır; çift çeneklide palizat-sünger ayrımı ve ağsı damar bulunur"},{"q":"Bir yaprağın stomalarının gün içinde açık, gece çoğunlukla kapalı olmasının fotosentez ve su dengesi açısından mantığını açıklayınız.","steps":[{"t":"Gündüz açıklık","a":"CO2 girişi","d":"Gündüz fotosentez için ışık vardır ve karbondioksit gereklidir. Stomalar açılarak CO2 girişini ve fotosentez için gerekli gaz alışverişini sağlar."},{"t":"Gündüz maliyeti","a":"Su kaybı","d":"Stomalar açıkken kaçınılmaz olarak su buharı da kaybedilir, yani terleme olur. Bu maliyet fotosentez kazancı yanında kabul edilir."},{"t":"Gece kapalılık","a":"Fotosentez yok","d":"Gece ışık olmadığından fotosentez yapılamaz ve CO2 girişine gerek kalmaz. Bu yüzden çoğu bitki gece stomalarını kapatır."},{"t":"Gece kazancı","a":"Su korunur","d":"Gece stomaların kapalı olması gereksiz su kaybını önler. Böylece bitki suyunu korurken hiçbir fotosentez fırsatı kaçırmaz."}],"ans":"Gündüz fotosentez için CO2 gerektiğinden stomalar açılır; gece fotosentez olmadığından kapanarak gereksiz su kaybı önlenir"},{"q":"CAM bitkilerinin (örneğin kaktüs) stoma davranışı sıradan bitkilerden nasıl farklıdır ve bu fark yaprak/gövde yapısıyla nasıl ilişkilidir?","steps":[{"t":"Sıradan davranış","a":"Gündüz açık","d":"Tipik bitkilerde stomalar gündüz açılıp gece kapanır, böylece fotosentez ile CO2 alımı eş zamanlıdır. Ancak bu, sıcak gündüzde yüksek su kaybına yol açar."},{"t":"CAM davranışı","a":"Gece açık","d":"CAM bitkilerinde stomalar serin gece açılır ve CO2 yi alıp organik asit olarak depolar. Sıcak gündüz ise stomalar kapanır."},{"t":"Gündüz aşaması","a":"Depodan CO2","d":"Gündüz kapalı stomalara rağmen, gece depolanan organik asitlerden CO2 açığa çıkar ve Calvin döngüsünde kullanılır. Böylece fotosentez su kaybetmeden sürdürülür."},{"t":"Yapı ilişkisi","a":"Etli su deposu","d":"CAM bitkileri genellikle kalın kütikulalı, etli (sukkulent) su depolayan dokulara sahiptir. Bu yapı ile gece-CO2 stratejisi birleşince aşırı kurak ortamda hayatta kalma sağlanır."}],"ans":"CAM bitkilerinde stomalar gece açılıp CO2 depolar, gündüz kapanır; etli su depolu yapılarıyla birlikte bu, kurak ortamda su kaybını en aza indirir"},{"q":"Yaprak yüzeyinde ışığın yansıtılması, soğurulması ve geçirilmesinin mezofil tabakalarının yapısıyla nasıl ilişkilendirildiğini açıklayınız.","steps":[{"t":"Üst yüzey","a":"Bir kısmı yansır","d":"Yaprağın parlak kütikulası gelen ışığın bir bölümünü yansıtarak aşırı ısınmayı ve hasarı sınırlar. Geri kalan ışık yaprak içine girer."},{"t":"Palizat soğurması","a":"Yoğun emilim","d":"İçeri giren ışığın büyük kısmı bol kloroplastlı palizat parankimasında soğurulur. Dik dizilim ışığın hücreler arasında yönlendirilip verimli yakalanmasını sağlar."},{"t":"Sünger saçılması","a":"Işık dağılımı","d":"Palizattan geçen ışık, sünger parankimasındaki hava boşluklarında saçılır ve içerideki kloroplastlarca yeniden yakalanır. Bu saçılma ışığın yaprak içinde daha uzun yol almasını sağlar."},{"t":"Sonuç","a":"Verimli kullanım","d":"Böylece yansıyan ışık koruma, soğurulan ışık fotosentez sağlar, saçılan ışık ise verimi artırır. Mezofil yapısı ışığın en etkin kullanımına göre düzenlenmiştir."}],"ans":"Kütikula bir kısmı yansıtır, palizat ışığı yoğun soğurur, sünger boşlukları ışığı saçarak yeniden yakalatır; mezofil yapısı ışığı verimli kullanmaya göre düzenlidir"}]}},"stomaMek":{"ilkokul":{"kolay":[{"q":"Yaprakların yüzeyinde gaz alışverişini sağlayan küçük açıklıklara ne ad verilir?","steps":[{"t":"Yaprağı tanıyalım","a":"Yaprak yüzeyinde küçük delikler vardır","d":"Bitkilerin yaprakları dışarıdan düzgün görünse de yüzeyinde gözle görülmeyen çok küçük açıklıklar bulunur. Bu açıklıklar bitkinin nefes alıp vermesine yardımcı olur."},{"t":"Açıklığın adı","a":"Bu açıklıklara stoma denir","d":"Yapraktaki bu küçük açıklıklara stoma (gözenek) adı verilir. Stomalar hava ile bitki arasındaki gaz alışverişini sağlar."}],"ans":"Stoma (gözenek) denir."},{"q":"Stomanın açılıp kapanmasını sağlayan iki hücreye ne ad verilir?","steps":[{"t":"Stomanın çevresi","a":"Stomanın yanında iki özel hücre vardır","d":"Her stomanın iki yanında onu çevreleyen özel hücreler bulunur. Bu hücreler stomanın açılıp kapanmasını kontrol eder."},{"t":"Hücrelerin adı","a":"Bu hücrelere bekçi (kilit) hücreleri denir","d":"Stomayı çevreleyen iki hücreye bekçi hücreleri (kilit hücreleri) denir. Onlar bir kapı gibi açıklığı açıp kapatır."}],"ans":"Bekçi (kilit) hücreleri denir."},{"q":"Bekçi hücrelerine su dolduğunda stoma açılır mı yoksa kapanır mı?","steps":[{"t":"Su girişi","a":"Bekçi hücreleri su ile şişer","d":"Bekçi hücrelerinin içine su girdiğinde hücreler şişer ve balon gibi dolar. Bu şişme hücrelerin şeklini değiştirir."},{"t":"Sonuç","a":"Hücreler şişince ortadaki açıklık genişler","d":"Bekçi hücreleri su ile şiştiğinde aralarındaki açıklık genişler ve stoma açılır. Böylece bitki gaz alışverişi yapabilir."}],"ans":"Stoma açılır."},{"q":"Stomalar bitki için en çok hangi gazı havadan alır?","steps":[{"t":"Bitkinin ihtiyacı","a":"Bitki besin üretmek için bir gaza ihtiyaç duyar","d":"Bitkiler güneş ışığında kendi besinlerini üretir. Bu işlem için havadan özel bir gaz almaları gerekir."},{"t":"Alınan gaz","a":"Bu gaz karbondioksittir","d":"Bitkiler stomalar yardımıyla havadan karbondioksit gazını alır. Bu gazı kullanarak besin ve oksijen üretirler."}],"ans":"Karbondioksit gazını alır."},{"q":"Stomalar çoğunlukla yaprağın hangi yüzünde daha fazla bulunur?","steps":[{"t":"Yaprağın iki yüzü","a":"Yaprağın üst ve alt yüzü vardır","d":"Bir yaprağın güneşe bakan üst yüzü ve gölgede kalan alt yüzü bulunur. Stomalar bu iki yüze eşit dağılmamıştır."},{"t":"Daha çok nerede?","a":"Alt yüzde daha fazla stoma vardır","d":"Stomalar genellikle yaprağın alt yüzünde daha çok bulunur. Böylece bitki güneşin sıcağında daha az su kaybeder."}],"ans":"Yaprağın alt yüzünde daha fazla bulunur."}],"zor":[{"q":"Karanlık bir gecede çoğu bitkide stomalar genellikle açık mı yoksa kapalı mı olur, neden?","steps":[{"t":"Işığın rolü","a":"Stomalar gündüz besin üretimine yardım eder","d":"Bitkiler gündüz ışıkta besin üretir ve bunun için karbondioksite ihtiyaç duyar. Bu yüzden gündüz stomaların açık olması işe yarar."},{"t":"Gece durumu","a":"Gece besin üretimi durur","d":"Karanlıkta ışık olmadığı için çoğu bitki besin üretemez ve karbondioksite o kadar ihtiyaç duymaz. Bu nedenle stomalar gece kapanma eğilimindedir."},{"t":"Sonuç","a":"Stomalar genellikle kapanır","d":"Geceleri çoğu bitkide stomalar kapanır, böylece boşuna su kaybedilmez. Bitki suyunu korumuş olur."}],"ans":"Genellikle kapalı olur; çünkü gece besin üretimi durduğundan karbondioksite ihtiyaç azalır ve su korunur."},{"q":"Bekçi hücrelerinden su çıkıp hücreler söndüğünde stomaya ne olur?","steps":[{"t":"Su kaybı","a":"Bekçi hücreleri suyunu kaybeder","d":"Bekçi hücrelerinden su dışarı çıktığında hücreler söner, tıpkı havası inen bir balon gibi. Hücrelerin şekli değişir."},{"t":"Şeklin değişmesi","a":"Sönen hücreler birbirine yaklaşır","d":"Su kaybeden bekçi hücreleri gevşer ve birbirine yaklaşır. Bu durumda aralarındaki açıklık daralır."},{"t":"Sonuç","a":"Açıklık kapanır","d":"Bekçi hücreleri söndüğünde stoma kapanır. Böylece bitkinin su kaybı azalır."}],"ans":"Stoma kapanır."},{"q":"Çok sıcak ve kurak bir günde bitki, su kaybını azaltmak için stomalarına ne yapar?","steps":[{"t":"Sıcak günün etkisi","a":"Sıcakta su buharlaşması artar","d":"Çok sıcak ve kurak günlerde bitkiden su daha hızlı buharlaşır. Bu durum bitkinin susuz kalmasına yol açabilir."},{"t":"Bitkinin tedbiri","a":"Bitki su kaybını azaltmak ister","d":"Susuz kalmamak için bitkinin su kaybını kontrol etmesi gerekir. Bunu stomalarını yöneterek yapar."},{"t":"Sonuç","a":"Stomalarını kapatır","d":"Bitki çok sıcakta stomalarını kapatarak su buharının çıkışını engeller. Böylece kıymetli suyunu korur."}],"ans":"Stomalarını kapatır."},{"q":"Bitki, ürettiği oksijen gazını dışarıya en çok nereden verir?","steps":[{"t":"Oksijenin oluşması","a":"Bitki besin üretirken oksijen açığa çıkarır","d":"Bitkiler ışıkta besin üretirken oksijen gazı oluşur. Bu gazın bitkiden dışarı çıkması gerekir."},{"t":"Çıkış yolu","a":"Gazlar yapraktaki açıklıklardan geçer","d":"Bitki gazları yaprak yüzeyindeki küçük açıklıklardan alıp verir. Oksijen de bu yoldan dışarı çıkar."},{"t":"Sonuç","a":"Oksijen stomalardan verilir","d":"Bitki ürettiği oksijeni en çok stomalardan dışarı verir. Bu oksijeni canlılar soluk almak için kullanır."}],"ans":"Stomalardan (yapraktaki gözeneklerden) verir."},{"q":"Stomalar kapalıyken bitkinin besin üretmesi neden zorlaşır?","steps":[{"t":"Besin için gereken gaz","a":"Besin üretimi karbondioksit ister","d":"Bitki besin üretmek için havadan karbondioksit almak zorundadır. Bu gaz olmadan üretim yapamaz."},{"t":"Kapalı stoma","a":"Kapalı stomadan gaz giremez","d":"Stomalar kapandığında havadaki karbondioksit yaprağın içine giremez. Yani bitkiye gerekli gaz ulaşamaz."},{"t":"Sonuç","a":"Karbondioksit azalır, üretim yavaşlar","d":"Karbondioksit içeri giremediği için bitkinin besin üretimi zorlaşır ve yavaşlar. Stomanın kapanması bu yüzden üretimi etkiler."}],"ans":"Kapalı stomadan karbondioksit giremediği için besin üretimi yavaşlar."}]},"ortaokul":{"kolay":[{"q":"Stomanın açılıp kapanmasını sağlayan asıl olay bekçi hücrelerinde nedir?","steps":[{"t":"Bekçi hücreleri","a":"Bekçi hücreleri stomayı çevreler","d":"Stomanın iki yanında bekçi (kilit) hücreleri bulunur. Bu hücreler stomanın genişliğini denetler."},{"t":"Asıl olay","a":"Su giriş çıkışı şekli değiştirir","d":"Bekçi hücrelerine su girip çıkması, onların turgor durumunu değiştirir. Su girince şişer, çıkınca söner."},{"t":"Sonuç","a":"Turgor değişimi açıklığı belirler","d":"Hücrelerdeki su miktarının (turgor) değişmesi stomanın açılıp kapanmasını sağlar. Yani temel mekanizma su hareketidir."}],"ans":"Bekçi hücrelerine su girip çıkması (turgor değişimi) stomayı açıp kapatır."},{"q":"Bekçi hücreleri turgor basıncını artırdığında stoma neden açılır?","steps":[{"t":"Turgor artışı","a":"Su girince hücreler şişer","d":"Bekçi hücrelerine su girdiğinde içlerindeki turgor basıncı artar ve hücreler şişer. Bu şişme hücre çeperini etkiler."},{"t":"Çeperin esnemesi","a":"Hücreler dışa doğru bükülür","d":"Şişen bekçi hücreleri eğilerek birbirinden uzaklaşır. Aralarında bir boşluk oluşur."},{"t":"Sonuç","a":"Açıklık genişler","d":"Bekçi hücreleri arasında oluşan boşluk stoma açıklığını oluşturur. Turgor arttıkça stoma açılır."}],"ans":"Turgor artınca bekçi hücreleri şişip dışa bükülerek arada açıklık oluştuğu için stoma açılır."},{"q":"Stomalar açıldığında yapraktan dışarı çıkan iki madde nedir?","steps":[{"t":"Açık stoma","a":"Açık stoma içeri ve dışarı geçişe izin verir","d":"Stoma açıldığında yaprağın içi ile dış hava arasında serbest geçiş olur. Bazı gazlar girer, bazıları çıkar."},{"t":"Dışarı çıkanlar","a":"Oksijen ve su buharı çıkar","d":"Bitki besin üretiminde oluşan oksijeni ve içindeki suyun buharını stomalardan dışarı verir. Aynı anda karbondioksiti içeri alır."}],"ans":"Oksijen gazı ve su buharı çıkar."},{"q":"Bekçi hücrelerinin diğer epidermis hücrelerinden farkı olarak hangi yapıyı bulundururlar?","steps":[{"t":"Epidermis hücreleri","a":"Epidermisin çoğu hücresinde belirli bir yapı yoktur","d":"Yaprak epidermisindeki sıradan hücreler genellikle renksizdir ve besin üretemez. Bunlar koruyucu bir tabaka oluşturur."},{"t":"Bekçi hücrenin özelliği","a":"Bekçi hücrelerinde kloroplast bulunur","d":"Bekçi hücreleri diğer epidermis hücrelerinden farklı olarak kloroplast içerir. Bu sayede besin üretimine katılabilir ve şeker üreterek su alımına yardımcı olur."}],"ans":"Kloroplast bulundururlar."},{"q":"Stomaların yaprağın alt yüzünde daha fazla olması bitkiye hangi avantajı sağlar?","steps":[{"t":"Üst ve alt yüz","a":"Üst yüz güneşe, alt yüz gölgeye bakar","d":"Yaprağın üst yüzü doğrudan güneş ışığı ve sıcaklık alırken alt yüz daha serin ve gölgelidir. Bu fark su kaybını etkiler."},{"t":"Su kaybı","a":"Sıcak yüzeyden su daha çok buharlaşır","d":"Sıcak ve güneşli üst yüzde su buharlaşması fazladır. Stomalar burada çok olsaydı bitki çok su kaybederdi."},{"t":"Avantaj","a":"Alt yüzde su kaybı azalır","d":"Stomalar serin alt yüzde yoğunlaştığı için terleme ile kaybedilen su miktarı azalır. Böylece bitki suyunu daha iyi korur."}],"ans":"Serin alt yüzde toplanmaları, terleme ile su kaybını azaltır."}],"zor":[{"q":"Bekçi hücrelerinin stoma açılırken neden iç içe bükülmeyip dışa doğru büküldüğünü açıklayınız.","steps":[{"t":"Çeper kalınlığı","a":"Bekçi hücre çeperi her yerde eşit kalın değildir","d":"Bekçi hücrelerinin stomaya bakan iç çeperi kalın, dışa bakan çeperi ise incedir. Bu eşit olmayan kalınlık önemlidir."},{"t":"Su girince","a":"İnce çeper daha çok esner","d":"Hücreye su girip turgor arttığında ince olan dış çeper daha kolay esner ve uzar. Kalın iç çeper ise az gerilir."},{"t":"Sonuç","a":"Hücre dışa doğru kıvrılır","d":"İnce dış çeper fazla uzayınca hücre dışa doğru bükülür ve iç çeperler birbirinden uzaklaşır. Böylece ortadaki açıklık genişleyip stoma açılır."}],"ans":"Çeperin iç tarafı kalın, dış tarafı ince olduğundan su girince ince dış çeper daha çok esner ve hücre dışa doğru bükülerek stoma açılır."},{"q":"Potasyum (K) iyonunun bekçi hücrelerine girişi stomanın açılmasını nasıl tetikler?","steps":[{"t":"İyon girişi","a":"Bekçi hücrelerine potasyum iyonu girer","d":"Stoma açılmadan önce bekçi hücrelerine bol miktarda potasyum (K) iyonu taşınır. Bu iyon hücre içi yoğunluğunu değiştirir."},{"t":"Suyun çekilmesi","a":"Artan yoğunluk suyu içeri çeker","d":"Hücre içindeki çözünmüş madde yoğunluğu artınca su osmozla bekçi hücrelerine girer. İyon yoğunluğu suyu bir mıknatıs gibi çeker."},{"t":"Sonuç","a":"Turgor artar, stoma açılır","d":"İçeri giren su bekçi hücrelerinin turgor basıncını artırır ve hücreler şişer. Böylece bekçi hücreleri dışa bükülüp stoma açılır."}],"ans":"Potasyum girişi hücre içi yoğunluğu artırır, su osmozla içeri girer, turgor yükselir ve stoma açılır."},{"q":"Su kıtlığı çeken bir bitkide bekçi hücreleri turgorunu kaybedince hangi olaylar sırasıyla gerçekleşir?","steps":[{"t":"Su azlığı","a":"Bitki yeterli su bulamaz","d":"Toprakta su azaldığında bitkinin hücrelerine yeterince su gitmez. Bekçi hücreleri de yeterli suyu alamaz."},{"t":"Turgor kaybı","a":"Bekçi hücreleri söner","d":"Su kaybeden bekçi hücrelerinin turgor basıncı düşer ve hücreler gevşeyip söner. Şişkin hücreler artık dik duramaz."},{"t":"Sonuç","a":"Stoma kapanır, su kaybı azalır","d":"Sönen bekçi hücreleri birbirine yaklaşır ve stoma kapanır. Böylece terleme ile su kaybı azalarak bitki kuruma riskinden korunur."}],"ans":"Bekçi hücreleri su kaybedip turgorunu yitirir, söner ve birbirine yaklaşır; stoma kapanarak su kaybı azalır."},{"q":"Bir bitki yaprağında stomaların tamamı uzun süre kapalı kalırsa hem gaz alışverişi hem de sıcaklık açısından ne gibi sorunlar oluşur?","steps":[{"t":"Gaz alışverişi","a":"Kapalı stomadan gaz geçmez","d":"Stomalar kapalıyken havadan karbondioksit içeri giremez ve içerideki oksijen dışarı çıkamaz. Gaz alışverişi büyük ölçüde durur."},{"t":"Besin üretimi","a":"Karbondioksit bitince üretim durur","d":"Yaprağın içindeki karbondioksit besin üretiminde tükenir ve yenisi giremez. Bu yüzden besin üretimi yavaşlar ya da durur."},{"t":"Sıcaklık","a":"Terleme olmayınca yaprak ısınır","d":"Stomalar kapalıyken su buharı çıkamaz, bu da terleme ile sağlanan serinlemeyi durdurur. Sonuçta yaprak fazla ısınabilir ve zarar görebilir."}],"ans":"Karbondioksit giremediği için besin üretimi durur, ayrıca terleme olmadığından yaprak serinleyemez ve aşırı ısınabilir."},{"q":"Bol ışık, yeterli su ve uygun karbondioksit ortamında stomaların açık olması bitkiye neden avantaj sağlar?","steps":[{"t":"Uygun koşullar","a":"Işık, su ve karbondioksit yeterlidir","d":"Bol ışık besin üretimi için enerji sağlar, yeterli su ise stomaları açık tutmaya el verir. Bu koşullarda bitki su kaybından çok endişe etmez."},{"t":"Açık stoma","a":"Açık stoma karbondioksit girişine izin verir","d":"Stomalar açık olduğunda havadan bol karbondioksit yaprağa girer. Bu gaz besin üretiminin temel hammaddesidir."},{"t":"Sonuç","a":"Besin üretimi en yüksek olur","d":"Işık, su ve karbondioksit birlikte bulununca bitki en çok besini üretir. Stomaların açık kalması bu yüksek üretimi mümkün kılar."}],"ans":"Açık stomalardan bol karbondioksit girdiği ve koşullar uygun olduğu için besin üretimi en yüksek düzeye çıkar."}]},"lise":{"kolay":[{"q":"Stoma yapısı; bekçi hücreleri ve komşu (yardımcı) hücreler bakımından genel olarak nasıl tanımlanır?","steps":[{"t":"Tanım","a":"Stoma bir açıklık ve onu çevreleyen hücrelerden oluşur","d":"Stoma, yaprak epidermisinde bulunan ve por adı verilen açıklık ile bunu çevreleyen iki bekçi hücresinden oluşur. Bu yapı gaz alışverişini düzenler."},{"t":"Komşu hücreler","a":"Bekçi hücrelerin çevresinde yardımcı hücreler olabilir","d":"Birçok bitkide bekçi hücrelerinin etrafında komşu (yardımcı/arkadaş) hücreler bulunur. Bunlar iyon ve su alışverişinde bekçi hücrelerine destek olur."},{"t":"İşlev","a":"Yapı bütün olarak gaz ve su geçişini ayarlar","d":"Bekçi hücreleri açıklığın genişliğini denetlerken komşu hücreler bu sürece katkı sağlar. Böylece stoma kompleksi gaz alışverişi ve terlemeyi yönetir."}],"ans":"Stoma; ortadaki por (açıklık), iki bekçi hücresi ve çoğu kez çevredeki komşu (yardımcı) hücrelerden oluşan bir yapıdır."},{"q":"Bekçi hücrelerinin sahip olduğu kloroplast, stoma mekanizmasında nasıl rol oynar?","steps":[{"t":"Kloroplastın varlığı","a":"Bekçi hücrelerinde kloroplast bulunur","d":"Diğer epidermis hücrelerinin aksine bekçi hücreleri kloroplast içerir. Bu, bekçi hücrelerinin fotosentez yapabilmesini sağlar."},{"t":"Şeker üretimi","a":"Fotosentezle çözünür madde oluşur","d":"Işıkta bekçi hücrelerindeki kloroplastlar fotosentez yaparak şeker gibi çözünür maddeler üretir. Bu maddeler hücre içi yoğunluğu artırır."},{"t":"Sonuç","a":"Osmotik su girişi kolaylaşır","d":"Artan çözünen yoğunluğu osmozla suyu bekçi hücrelerine çeker ve turgoru yükseltir. Böylece kloroplastlar dolaylı olarak stomanın açılmasını destekler."}],"ans":"Kloroplastlar fotosentezle çözünür madde üretip hücre içi yoğunluğu artırır; bu da osmozla su girişini ve stoma açılmasını destekler."},{"q":"Bekçi hücre çeperinin eşit olmayan kalınlığı stoma açılışında neden gereklidir?","steps":[{"t":"Çeper yapısı","a":"İç çeper kalın, dış çeper incedir","d":"Bekçi hücrelerinin pore (açıklığa) bakan iç çeperi kalın ve esnemeye dirençli, dışa bakan çeperi ise ince ve esnektir. Bu asimetri kritik öneme sahiptir."},{"t":"Turgor etkisi","a":"Su girince ince çeper daha çok genişler","d":"Turgor arttığında ince dış çeper, kalın iç çepere göre çok daha fazla uzar. Bu farklı esneme hücrenin şeklini belirler."},{"t":"Sonuç","a":"Hücre dışa kıvrılarak açıklık oluşturur","d":"İnce dış çeperin fazla uzaması hücreyi dışa bükerek iç çeperleri birbirinden uzaklaştırır. Eğer çeper her yerde eşit kalın olsaydı hücre yalnızca şişip büyür, açıklık oluşmazdı."}],"ans":"İnce dış çeper kalın iç çepere göre daha çok esnediğinden hücre dışa bükülür; çeper eşit kalın olsaydı açıklık oluşmazdı."},{"q":"Stoma açılırken bekçi hücrelerine potasyum iyonu girişi ile su girişi arasındaki bağlantı nedir?","steps":[{"t":"İyon birikimi","a":"Bekçi hücrelerine K iyonu pompalanır","d":"Stoma açılmaya başlarken bekçi hücrelerine aktif taşımayla potasyum (K) iyonları girer. Genellikle bunu dengelemek için klorür ve malat gibi negatif yükler de birikir."},{"t":"Su potansiyeli","a":"İyon birikimi su potansiyelini düşürür","d":"Çözünmüş iyon miktarı arttıkça hücrenin su potansiyeli (osmotik basıncı) düşer. Bu, suyu hücreye çekecek bir koşul oluşturur."},{"t":"Sonuç","a":"Su osmozla içeri girer, turgor artar","d":"Düşen su potansiyeli nedeniyle su osmozla bekçi hücrelerine girer ve turgor yükselir. Yani potasyum girişi, su girişinin ardından gelen turgor artışını tetikler."}],"ans":"Potasyum girişi hücrenin su potansiyelini düşürür, bu da osmozla suyu içeri çeker ve turgoru artırarak stomayı açar."},{"q":"Işık, stomaların açılmasını hangi genel mekanizmalarla teşvik eder?","steps":[{"t":"Işık alıcıları","a":"Bekçi hücrelerinde ışığa duyarlı yapılar vardır","d":"Bekçi hücreleri mavi ışık alıcıları ve kloroplast içerir. Işık bu yapıları uyararak iyon pompalarını harekete geçirir."},{"t":"İyon ve şeker","a":"Işık potasyum girişi ve fotosentezi artırır","d":"Işıkta hücreye potasyum girişi artar ve fotosentezle çözünür şekerler üretilir. Her iki olay da hücre içi çözünen yoğunluğunu yükseltir."},{"t":"Sonuç","a":"Su girer ve stoma açılır","d":"Artan çözünen yoğunluğu osmozla su girişini sağlar, turgor yükselir ve stoma açılır. Böylece ışık, gündüz fotosentez için gerekli karbondioksitin alımını kolaylaştırır."}],"ans":"Işık iyon pompalarını ve fotosentezi uyararak çözünen yoğunluğu artırır, su içeri girer ve stoma açılır."},{"q":"Yaprak içi karbondioksit derişiminin düşük olması stomaları nasıl etkiler?","steps":[{"t":"CO2 algılaması","a":"Bekçi hücreleri yaprak içi karbondioksiti algılar","d":"Bekçi hücreleri yaprak boşluklarındaki karbondioksit derişimine duyarlıdır. Bu derişim fotosentez hızına bağlı olarak değişir."},{"t":"Düşük CO2","a":"Fotosentez CO2 derişimini düşürür","d":"Bitki yoğun fotosentez yaptığında yaprak içindeki karbondioksit hızla tüketilir ve derişimi düşer. Bu durum bitkiye daha çok CO2 gerektiğini bildirir."},{"t":"Sonuç","a":"Stomalar açılır","d":"Düşük karbondioksit derişimi bekçi hücrelerini uyararak stomaların açılmasına yol açar. Böylece dışarıdan daha fazla karbondioksit alınır."}],"ans":"Yaprak içi düşük karbondioksit derişimi stomaların açılmasını teşvik ederek dışarıdan CO2 alımını artırır."},{"q":"Stomalardan gerçekleşen gaz alışverişinde giren ve çıkan başlıca maddeler nelerdir?","steps":[{"t":"Giren gaz","a":"Karbondioksit içeri alınır","d":"Stomalar açıkken fotosentez için gerekli karbondioksit yaprağa girer. Bu, besin üretiminin hammaddesidir."},{"t":"Çıkan gazlar","a":"Oksijen ve su buharı dışarı verilir","d":"Fotosentezde oluşan oksijen ve hücrelerden buharlaşan su, stomalardan dışarı çıkar. Su buharı çıkışı terlemenin bir parçasıdır."},{"t":"Denge","a":"Solunum gazları da geçer","d":"Bitki solunum yaptığı için karbondioksit çıkışı ve oksijen girişi de olur; ancak gündüz fotosentez baskındır. Bu yüzden net olarak CO2 girer, O2 ve su buharı çıkar."}],"ans":"Karbondioksit içeri girer; oksijen ve su buharı dışarı çıkar."},{"q":"Çöl bitkilerinin (CAM bitkileri gibi) stomalarını gece açıp gündüz kapatması hangi avantajı sağlar?","steps":[{"t":"Çöl koşulu","a":"Gündüz sıcak ve kuraktır","d":"Çöllerde gündüz çok sıcak ve kurudur, bu yüzden açık stomadan büyük miktarda su kaybedilir. Su, çöl bitkileri için en kıt kaynaktır."},{"t":"Gece stratejisi","a":"Gece stomalar açılır","d":"Bu bitkiler gece serin ve nemli olduğunda stomalarını açıp karbondioksiti alır ve depolar. Gündüz ise stomaları kapalı tutarak suyu korur."},{"t":"Sonuç","a":"Su korunur, fotosentez sürer","d":"Gece alınan karbondioksit gündüz kapalı stomalarla fotosentezde kullanılır. Böylece bitki hem su kaybını en aza indirir hem de besin üretimini sürdürür."}],"ans":"Gündüz stomaları kapalı tutup su kaybını azaltırken, geceleri açarak depoladıkları CO2 ile gündüz fotosentez yapabilirler."},{"q":"Stomanın açık ve kapalı durumlarında su potansiyeli açısından bekçi hücrelerinin durumu nasıl farklılaşır?","steps":[{"t":"Açık durum","a":"Bekçi hücrelerinde su potansiyeli düşüktür","d":"Stoma açıkken bekçi hücrelerinde çözünmüş madde (potasyum, şeker) çoktur, bu da su potansiyelini düşürür. Düşük su potansiyeli suyu hücreye çeker ve turgoru yüksek tutar."},{"t":"Kapalı durum","a":"Çözünenler azalır, su potansiyeli yükselir","d":"Stoma kapanırken bekçi hücrelerinden iyonlar dışarı çıkar ve çözünen yoğunluğu azalır. Bu, su potansiyelini yükseltir ve su dışarı çıkar."},{"t":"Sonuç","a":"Turgor durumu açıklığı belirler","d":"Açıkken yüksek turgor, kapalıyken düşük turgor söz konusudur. Bekçi hücrelerinin su potansiyeli değişimi doğrudan stoma açıklığını belirler."}],"ans":"Açıkken bekçi hücrelerinin su potansiyeli düşük ve turgoru yüksektir; kapalıyken su potansiyeli yükselip turgor düşer."},{"q":"Stomaların düzgün çalışması bitkinin hem fotosentez hem de terleme dengesini nasıl etkiler?","steps":[{"t":"Çift işlev","a":"Stoma hem CO2 alır hem su kaybeder","d":"Stoma açıldığında fotosentez için karbondioksit girerken aynı anda su buharı çıkar. Bu nedenle bitki sürekli bir denge sorunuyla karşı karşıyadır."},{"t":"Açıklık ayarı","a":"Bitki açıklığı koşullara göre ayarlar","d":"Bitki ışık, su ve karbondioksit durumuna göre stomanın ne kadar açık olacağını ayarlar. Böylece hem yeterli CO2 alır hem de aşırı su kaybetmemeye çalışır."},{"t":"Sonuç","a":"Optimum denge sağlanır","d":"Stomaların düzgün açılıp kapanması, fotosentez verimi ile su tasarrufu arasında en uygun dengeyi kurar. Bu denge bitkinin hayatta kalması için kritik öneme sahiptir."}],"ans":"Stomalar açıklığı ayarlayarak yeterli CO2 alımı ile en az su kaybı arasında fotosentez-terleme dengesini sağlar."},{"q":"Bekçi hücrelerinin çevresindeki komşu (yardımcı) hücrelerin stoma çalışmasındaki rolü nedir?","steps":[{"t":"Komşu hücreler","a":"Bekçi hücrelerin yanında özel hücreler vardır","d":"Birçok bitkide bekçi hücrelerini çevreleyen komşu (yardımcı) hücreler bulunur. Bunlar sıradan epidermis hücrelerinden işlevsel olarak farklıdır."},{"t":"İyon deposu","a":"İyon ve su alışverişine katılırlar","d":"Komşu hücreler, stoma açılırken bekçi hücrelerine geçecek potasyum gibi iyonlar için bir kaynak ve depo görevi görür. Stoma kapanırken de iyonları geri alabilirler."},{"t":"Sonuç","a":"Hızlı ve verimli açılma sağlanır","d":"Komşu hücreler iyon alışverişini kolaylaştırarak stomanın daha hızlı ve verimli açılıp kapanmasına yardımcı olur. Böylece bitki koşullara çabuk uyum sağlar."}],"ans":"Komşu hücreler iyon ve su alışverişinde bekçi hücrelerine kaynak/depo olarak destek vererek stomanın hızlı açılıp kapanmasını sağlar."},{"q":"Stomaların büyük çoğunluğunun yaprağın alt yüzünde bulunması (kara bitkileri için) hangi uyumu yansıtır?","steps":[{"t":"Yüzey farkı","a":"Üst yüz daha sıcak ve güneşlidir","d":"Yaprağın üst yüzü doğrudan güneş ışığına maruz kaldığı için daha sıcaktır ve buradan su buharlaşması fazladır. Alt yüz ise daha serin ve gölgelidir."},{"t":"Su tasarrufu","a":"Stomalar serin alt yüzde yoğunlaşır","d":"Stomalar daha serin olan alt yüzde toplanırsa terleme ile su kaybı azalır. Bu, özellikle kuraklığa eğilimli ortamlarda avantaj sağlar."},{"t":"Sonuç","a":"Su kaybını azaltan bir uyum","d":"Alt yüzde stoma yoğunluğunun fazla olması, bitkinin gaz alışverişini sürdürürken su kaybını en aza indirmesini sağlayan çevresel bir uyumdur. Su yüzeyinde yüzen bitkilerde ise tersine üst yüzde bulunur."}],"ans":"Serin alt yüzde toplanmaları, gaz alışverişini sürdürürken terleme ile su kaybını azaltan bir uyumu yansıtır."},{"q":"Bekçi hücrelerinin söndüğü (gevşediği) durumda stomanın kapanma sürecini sırayla açıklayınız.","steps":[{"t":"İyon çıkışı","a":"Bekçi hücrelerinden iyonlar dışarı çıkar","d":"Stoma kapanması başlarken bekçi hücrelerinden potasyum ve diğer çözünenler dışarı taşınır. Bu, hücre içi çözünen yoğunluğunu düşürür."},{"t":"Su çıkışı","a":"Su potansiyeli yükselince su dışarı çıkar","d":"Çözünen azaldıkça hücrenin su potansiyeli yükselir ve su osmozla dışarı çıkar. Bekçi hücrelerinin turgoru hızla düşer."},{"t":"Sonuç","a":"Hücreler söner, stoma kapanır","d":"Turgorunu kaybeden bekçi hücreleri gevşeyerek birbirine yaklaşır ve aralarındaki açıklık kapanır. Böylece gaz alışverişi ve terleme azalır."}],"ans":"İyonlar dışarı çıkar, su potansiyeli yükselir, su dışarı çıkar, turgor düşer ve bekçi hücreleri gevşeyerek stoma kapanır."},{"q":"Kuraklık stresinde bitkide üretilen absisik asit (ABA) hormonu stomaları nasıl etkiler?","steps":[{"t":"Stres sinyali","a":"Su azalınca ABA hormonu üretilir","d":"Bitki kuraklık stresi altındayken absisik asit (ABA) adlı hormon üretilir ve bekçi hücrelerine ulaşır. Bu hormon su tasarrufu sinyalidir."},{"t":"İyon çıkışı","a":"ABA, bekçi hücrelerinden iyon çıkışını tetikler","d":"ABA, bekçi hücrelerinde iyonların dışarı atılmasına yol açar. Böylece hücre içi çözünen yoğunluğu düşer."},{"t":"Sonuç","a":"Su çıkar, stoma kapanır","d":"Çözünen azalınca su dışarı çıkar, turgor düşer ve stoma kapanır. ABA bu şekilde kuraklıkta su kaybını azaltan bir koruyucu rol oynar."}],"ans":"ABA bekçi hücrelerinden iyon ve su çıkışını tetikleyerek turgoru düşürür ve stomayı kapatarak su kaybını azaltır."},{"q":"Stomanın açık kalması fotosentez için gerekliyken aynı zamanda neden bir su kaybı maliyeti taşır?","steps":[{"t":"Açık stoma","a":"Açık stoma karbondioksit girişine izin verir","d":"Stoma açık olduğunda fotosentez için gerekli karbondioksit yaprağa serbestçe girer. Bu, besin üretiminin sürmesi için zorunludur."},{"t":"Aynı yol","a":"Su buharı da aynı açıklıktan çıkar","d":"Karbondioksitin girdiği aynı açıklıktan yaprak içindeki su buharı dışarı kaçar. Yani CO2 alımı ile su kaybı aynı yolu paylaşır."},{"t":"Sonuç","a":"Üretim ile su kaybı bir aradadır","d":"Bu nedenle fotosentez yapmak isteyen bitki kaçınılmaz olarak su kaybını da göze almak zorundadır. Bitki bu ödünleşmeyi stoma açıklığını ayarlayarak yönetir."}],"ans":"Karbondioksitin girdiği aynı açıklıktan su buharı çıktığı için fotosentez sürerken kaçınılmaz olarak su kaybı yaşanır."}],"zor":[{"q":"Stoma açılışındaki olayları su potansiyeli, osmotik potansiyel ve basınç potansiyeli kavramlarıyla sırasıyla açıklayınız.","steps":[{"t":"Çözünen birikimi","a":"İyon ve şeker girişi osmotik potansiyeli düşürür","d":"Bekçi hücrelerine potasyum, klorür ve fotosentezle üretilen şekerlerin birikmesi osmotik (çözünen) potansiyeli negatifleştirir. Çözünen arttıkça osmotik potansiyel düşer."},{"t":"Su potansiyeli","a":"Düşen osmotik potansiyel su potansiyelini düşürür","d":"Su potansiyeli, osmotik potansiyel ile basınç potansiyelinin toplamıdır. Çözünen artışıyla hücrenin su potansiyeli komşu hücrelerden daha düşük hale gelir."},{"t":"Su girişi","a":"Su yüksek potansiyelden düşüğe akar","d":"Su, potansiyeli yüksek olan çevre hücrelerden, potansiyeli düşük bekçi hücrelerine osmozla geçer. Bu su girişi bir sonraki adımı tetikler."},{"t":"Basınç artışı","a":"Basınç potansiyeli yükselir, stoma açılır","d":"İçeri giren su basınç (turgor) potansiyelini yükseltir ve bekçi hücreleri şişerek dışa bükülür. Böylece açıklık genişler ve stoma açılır."}],"ans":"Çözünen birikimi osmotik potansiyeli ve su potansiyelini düşürür, su osmozla girer, basınç potansiyeli (turgor) yükselir ve stoma açılır."},{"q":"Mavi ışığın stoma açılışındaki özel rolünü, kırmızı ışıktan ayıran mekanizmalarla açıklayınız.","steps":[{"t":"Mavi ışık alıcısı","a":"Bekçi hücrelerinde mavi ışık alıcıları vardır","d":"Bekçi hücreleri fototropin gibi mavi ışığa özgü alıcılar bulundurur. Bu alıcılar mavi ışığı algılayınca özel bir yanıt başlatır."},{"t":"Proton pompası","a":"Mavi ışık zar pompasını aktive eder","d":"Mavi ışık, hücre zarındaki proton pompasını uyararak hücre dışına proton atılmasını sağlar. Bu da membran boyunca bir elektrik gradyanı oluşturur ve potasyum girişini hızlandırır."},{"t":"Kırmızı ışık farkı","a":"Kırmızı ışık fotosentez yoluyla etkiler","d":"Kırmızı ışık ise daha çok fotosentezi uyararak yaprak içi karbondioksiti düşürür ve dolaylı olarak stomayı açar. Yani kırmızı ışığın etkisi büyük ölçüde fotosentez kaynaklıdır."},{"t":"Sonuç","a":"İki yolak birlikte açılışı sağlar","d":"Mavi ışık doğrudan iyon pompalarıyla hızlı açılış sağlarken, kırmızı ışık fotosentez üzerinden katkıda bulunur. Bu iki yolak birlikte stoma açılışını optimize eder."}],"ans":"Mavi ışık fototropin alıcılarıyla proton pompasını aktive edip potasyum girişini hızlandırır; kırmızı ışık ise fotosentezle CO2 düşürerek dolaylı etki eder."},{"q":"Bekçi hücre çeperindeki radyal yönelimli selüloz mikrofibrillerinin stoma açılışındaki mekanik rolünü açıklayınız.","steps":[{"t":"Mikrofibril yönelimi","a":"Selüloz fibrilleri radyal düzenlenmiştir","d":"Bekçi hücre çeperindeki selüloz mikrofibrilleri hücre çevresinde radyal (ışınsal) olarak dizilmiştir. Bu dizilim hücrenin nasıl şekil değiştireceğini belirler."},{"t":"Genişlemenin yönü","a":"Fibriller yana genişlemeyi engeller, boyuna uzamaya izin verir","d":"Radyal fibriller hücrenin enine (radyal) şişmesini sınırlar ve daha çok boyuna (uzunlamasına) uzamasını sağlar. Böylece su girince hücre genişlemekten çok uzar."},{"t":"İç çeperle birleşince","a":"Boyuna uzama, hücreyi dışa büker","d":"Hücrenin uzaması ve iç çeperin kalın olması birlikte hücreyi dışa doğru kavis yapar. İki bekçi hücresi yarımay (böbrek) şeklini alır."},{"t":"Sonuç","a":"Açıklık oluşur","d":"Yarımay biçimi alan iki hücrenin iç çeperleri birbirinden uzaklaşır ve ortada por açılır. Selüloz mikrofibrillerinin yönelimi bu mekanik açılışın temelidir."}],"ans":"Radyal selüloz mikrofibrilleri enine şişmeyi engelleyip boyuna uzamaya yol açar; kalın iç çeperle birlikte hücreyi yarımay biçiminde dışa bükerek açıklık oluşturur."},{"q":"Yüksek atmosferik CO2 derişiminin (örneğin küresel ısınma senaryosunda) stoma davranışı ve bitkinin su kullanımına olası etkilerini açıklayınız.","steps":[{"t":"CO2 algısı","a":"Yüksek CO2 stomaları kısmen kapatır","d":"Yaprak içi yüksek karbondioksit derişimi bekçi hücrelerini stomayı daraltmaya yöneltir. Çünkü bitki yeterli CO2ye zaten sahiptir."},{"t":"Su kullanımı","a":"Daha dar stoma su kaybını azaltır","d":"Stomalar daha az açık olduğunda terleme ile su kaybı azalır. Aynı miktarda CO2 alırken daha az su harcanır, yani su kullanım verimi artar."},{"t":"Uzun vadeli etki","a":"Stoma yoğunluğu da değişebilir","d":"Uzun süreli yüksek CO2 koşullarında bazı bitkiler yapraklarında daha az stoma geliştirir. Bu da gelecekte su kullanım dengesini değiştirebilir."},{"t":"Sonuç","a":"Su verimi artarken başka dengeler bozulabilir","d":"Yüksek CO2 bitkinin su kullanım verimini artırabilir, ancak terlemenin azalması yaprak sıcaklığını ve mineral taşınmasını da etkiler. Bu nedenle etkiler ekosistem ölçeğinde karmaşıktır."}],"ans":"Yüksek CO2 stomaları daraltıp terlemeyi azaltarak su kullanım verimini artırır; uzun vadede stoma yoğunluğu düşebilir, ancak mineral taşınması ve yaprak sıcaklığı dengesi etkilenebilir."},{"q":"Bekçi hücrelerinde potasyum girişini dengelemek için biriken negatif yüklerin (klorür ve malat) kaynaklarını ve rolünü açıklayınız.","steps":[{"t":"Yük dengesi sorunu","a":"Pozitif K iyonu yük dengesizliği yaratır","d":"Bekçi hücrelerine bol miktarda pozitif yüklü potasyum girince hücre içinde yük dengesizliği oluşur. Bu dengesizliğin giderilmesi gerekir."},{"t":"Klorür","a":"Dışarıdan klorür iyonu alınır","d":"Yük dengesini sağlamak için hücreye dışarıdan negatif yüklü klorür iyonları taşınır. Klorür, potasyumun pozitif yükünü kısmen dengeler."},{"t":"Malat","a":"Hücre içinde malat üretilir","d":"Ek olarak hücre, depo nişastayı parçalayarak organik bir asit olan malat üretir. Malat da negatif yük taşıyarak yük dengesine katkıda bulunur."},{"t":"Sonuç","a":"Dengeli çözünen birikimi turgoru artırır","d":"Klorür ve malatın katkısıyla hücre içi çözünen yoğunluğu güvenle artar ve su potansiyeli düşer. Böylece su girişi ve turgor artışı sağlıklı biçimde gerçekleşir."}],"ans":"Potasyumun pozitif yükünü dengelemek için dışarıdan klorür alınır ve nişasta parçalanarak malat üretilir; bu negatif yükler çözünen birikimini ve turgor artışını sağlar."},{"q":"Stoma açıklığının hem fotosentez hızını hem de su kaybını etkilediği ödünleşmeyi (trade-off) su kullanım verimi kavramıyla açıklayınız.","steps":[{"t":"Çift etki","a":"Açıklık hem CO2 girişini hem su çıkışını belirler","d":"Stoma ne kadar açıksa o kadar çok karbondioksit girer ve fotosentez hızı artar, ancak aynı oranda su buharı da çıkar. Aynı açıklık iki zıt sonucu birlikte doğurur."},{"t":"Verim tanımı","a":"Su kullanım verimi bir orandır","d":"Su kullanım verimi, alınan karbondioksit (veya üretilen besin) miktarının kaybedilen su miktarına oranıdır. Bitki bu oranı yüksek tutmaya çalışır."},{"t":"Optimizasyon","a":"Bitki açıklığı koşullara göre ayarlar","d":"Su bol ve ışık yeterliyken stomalar geniş açılır; su kıt olduğunda bitki açıklığı azaltarak suyu korur. Böylece her koşulda mümkün olan en yüksek verim hedeflenir."},{"t":"Sonuç","a":"Stoma kontrolü dengeyi sağlar","d":"Stoma açıklığının ince ayarı, fotosentez kazancı ile su kaybı maliyeti arasındaki dengeyi belirler. Bu ödünleşmeyi iyi yöneten bitkiler değişen ortamlarda daha başarılı olur."}],"ans":"Açık stoma hem CO2 alımını hem su kaybını artırır; bitki açıklığı koşullara göre ayarlayarak alınan CO2nin kaybedilen suya oranını (su kullanım verimini) en yüksek tutmaya çalışır."},{"q":"Su zambağı gibi yüzücü yapraklı su bitkilerinde stomaların yaprağın üst yüzünde yoğunlaşmasının nedenini açıklayınız.","steps":[{"t":"Konum farkı","a":"Yaprağın alt yüzü suya değer","d":"Yüzücü yapraklı su bitkilerinde yaprağın alt yüzü su ile temas halindedir, üst yüzü ise havaya açıktır. Bu, kara bitkilerinden farklı bir durum oluşturur."},{"t":"Gaz alışverişi sorunu","a":"Su altındaki yüzeyden gaz alışverişi zordur","d":"Stomalar alt yüzde olsaydı su, gaz alışverişini engellerdi çünkü su içinde gaz difüzyonu çok yavaştır. Ayrıca açık stomadan suyun içeri sızması riski olurdu."},{"t":"Üst yüz çözümü","a":"Stomalar havaya açık üst yüzde yoğunlaşır","d":"Havaya açık olan üst yüze yerleşen stomalar atmosferle doğrudan gaz alışverişi yapabilir. Böylece karbondioksit alımı ve oksijen çıkışı verimli olur."},{"t":"Sonuç","a":"Konuma uygun bir uyum","d":"Stomaların üst yüzde bulunması, su bitkisinin yaşam ortamına uygun bir uyumdur. Kara bitkilerinde tam tersine alt yüzde yoğunlaşmaları su kaybını azaltma uyumudur."}],"ans":"Su bitkilerinde alt yüz suyla temas halinde olduğundan gaz alışverişi yapılamaz; stomalar havaya açık üst yüzde yoğunlaşarak atmosferle gaz alışverişini sağlar."},{"q":"Stomaların gün içindeki açılıp kapanma ritmi (sirkadiyen ritim) bitkiye nasıl bir avantaj sağlar?","steps":[{"t":"İç saat","a":"Bitkilerin sirkadiyen iç saati vardır","d":"Bitkiler, çevredeki ışık olmasa bile gün içindeki zamanı kabaca izleyen bir iç saate (sirkadiyen ritim) sahiptir. Bu saat birçok süreci düzenler."},{"t":"Önceden hazırlık","a":"Stomalar şafaktan önce açılmaya hazırlanır","d":"Sirkadiyen ritim sayesinde stomalar gün doğmadan açılmaya başlar, böylece ışık geldiği anda fotosentez hemen başlar. Akşam ise kapanmaya önceden hazırlanır."},{"t":"Su yönetimi","a":"Öğle sıcağında geçici kapanma olabilir","d":"Birçok bitkide öğle saatlerinde stomalar kısmen kapanarak en sıcak ve kurak dönemde su kaybını azaltır. Bu, midday closure denilen davranıştır."},{"t":"Sonuç","a":"Verim ve su tasarrufu iyileşir","d":"Stomaların ritmik kontrolü, fotosentezin ışıkla uyumlu olmasını sağlarken su kaybını gün içinde akıllıca dağıtır. Bu da bitkinin genel verimini ve hayatta kalmasını artırır."}],"ans":"Sirkadiyen ritim stomaları şafaktan önce açılmaya hazırlayıp fotosentezi hızlı başlatır, öğle sıcağında kısmen kapatarak su kaybını yönetir; böylece verim ve su tasarrufu iyileşir."},{"q":"Bekçi hücrelerinde nişasta ve şeker dönüşümünün stoma açılıp kapanmasıyla ilişkisini açıklayınız.","steps":[{"t":"Gece deposu","a":"Bekçi hücreleri nişasta depolar","d":"Geceleri bekçi hücreleri kloroplastlarında nişasta biriktirir; nişasta çözünmeyen bir depo maddesidir. Çözünmediği için su potansiyelini fazla etkilemez."},{"t":"Gündüz dönüşümü","a":"Nişasta çözünür şekere dönüşür","d":"Gündüz ışıkta nişasta parçalanıp çözünür şekerlere (malat ve glikoz gibi) dönüşür. Bu çözünenler hücre içi yoğunluğu artırır."},{"t":"Su girişi","a":"Artan çözünen suyu çeker","d":"Çözünür madde artışı su potansiyelini düşürür ve osmozla su içeri girer. Turgor yükselir ve stoma açılır."},{"t":"Kapanma","a":"Şeker tekrar nişastaya çevrilir","d":"Stoma kapanırken şekerler yeniden çözünmeyen nişastaya dönüştürülür, çözünen azalır ve su çıkar. Böylece nişasta-şeker dönüşümü stoma ritmini destekler."}],"ans":"Gündüz nişasta çözünür şekere dönüşüp çözünen yoğunluğu artırır, su girer ve stoma açılır; kapanırken şeker tekrar nişastaya çevrilip çözünen azalır ve su çıkar."},{"q":"Hava nemi (bağıl nem) doğrudan stoma açıklığını nasıl etkileyebilir, mekanizmasını açıklayınız.","steps":[{"t":"Nem ve buharlaşma","a":"Düşük nemde buharlaşma artar","d":"Hava nemi düştüğünde yaprak yüzeyi ile hava arasındaki su buharı farkı artar ve terleme hızlanır. Bu, bekçi hücrelerini de etkiler."},{"t":"Bekçi hücre kaybı","a":"Bekçi hücreleri çevreye su kaybeder","d":"Kuru havada bekçi hücreleri ve çevresindeki epidermis hücreleri doğrudan su buharı kaybeder. Bu su kaybı bekçi hücrelerinin turgorunu düşürür."},{"t":"Açıklık tepkisi","a":"Turgor düşünce stoma daralır","d":"Turgorunu kaybetmeye başlayan bekçi hücreleri sönerek stomayı daraltır veya kapatır. Yani bitki çok kuru havada stomayı kısar."},{"t":"Sonuç","a":"Nem stoma açıklığını dengeler","d":"Yüksek nemde stomalar daha rahat açık kalırken düşük nemde daralma eğilimindedir. Böylece bitki ortam nemine göre su kaybını dengeler."}],"ans":"Düşük nemde terleme artıp bekçi hücreleri su kaybedince turgor düşer ve stoma daralır; yüksek nemde stomalar daha rahat açık kalır."},{"q":"Stomanın açılıp kapanmasında aktif taşıma (enerji harcayan) ve pasif osmoz (enerji harcamayan) süreçlerini ayırt ederek açıklayınız.","steps":[{"t":"Aktif taşıma","a":"İyon hareketleri enerji gerektirir","d":"Bekçi hücrelerine potasyum gibi iyonların pompalanması ve proton pompalarının çalışması ATP enerjisi gerektiren aktif taşımadır. Bu, derişim farkına karşı yapılır."},{"t":"Pasif osmoz","a":"Su hareketi enerji gerektirmez","d":"İyon birikimiyle su potansiyeli düştüğünde su, yüksek potansiyelden düşüğe doğru kendiliğinden (pasif) hareket eder. Osmoz için hücre doğrudan enerji harcamaz."},{"t":"Sıralama","a":"Önce aktif taşıma, sonra pasif osmoz","d":"Önce enerji harcanarak iyonlar taşınır ve çözünen birikir; ardından su bu birikime tepki olarak pasifçe içeri akar. Yani enerji harcayan adım, enerji harcamayan su hareketini yönlendirir."},{"t":"Sonuç","a":"İki süreç birlikte turgoru ayarlar","d":"Aktif iyon taşıması osmotik koşulu kurar, pasif osmoz ise turgoru gerçekleştirir. Bu iş bölümü stomanın hassas ve enerji açısından verimli çalışmasını sağlar."}],"ans":"İyonların pompalanması ATP harcayan aktif taşımadır; su girişi ise enerji harcamayan pasif osmozdur. Aktif taşıma osmotik koşulu kurar, ardından su pasifçe hareket ederek turgoru ve stoma açıklığını belirler."},{"q":"İğne yapraklı (kozalaklı) bitkilerde stomaların çukurlara gömülü olması ve mum tabakası ile örtülmesinin işlevini açıklayınız.","steps":[{"t":"Zor ortam","a":"Kozalaklılar kurak ve soğuk ortamlarda yaşar","d":"İğne yapraklı bitkiler çoğunlukla suyun sınırlı olduğu soğuk veya kurak ortamlarda yaşar. Bu koşullarda su kaybını en aza indirmek hayati önem taşır."},{"t":"Gömülü stoma","a":"Stomalar yüzeyden içeri çukurda bulunur","d":"Bu bitkilerde stomalar yaprak yüzeyinin altında çukurlara gömülmüştür. Çukurun içinde durgun, nemli bir hava tabakası oluşur."},{"t":"Mum tabakası","a":"Yüzey kalın mumsu kütikula ile kaplıdır","d":"İğne yapraklar kalın mumsu bir kütikula tabakasıyla örtülüdür ve çukurlar da kıllarla dolu olabilir. Bu yapı su buharının doğrudan kaçmasını zorlaştırır."},{"t":"Sonuç","a":"Terleme azalır, su korunur","d":"Gömülü stoma çevresindeki nemli durgun hava ve kalın mum tabakası terleme ile su kaybını büyük ölçüde azaltır. Böylece bitki kurak ve soğuk koşullarda hayatta kalabilir."}],"ans":"Gömülü stomalar çevresinde nemli durgun hava oluşur, kalın mum tabakası da buharlaşmayı zorlaştırır; bu yapılar terleme ile su kaybını azaltarak kurak ve soğuk ortamlarda hayatta kalmayı sağlar."},{"q":"Bir yaprakta stomaların açıklık derecesini ölçmenin (örneğin gözenek iletkenliği) bitki su durumu hakkında neden bilgi verdiğini açıklayınız.","steps":[{"t":"Açıklık göstergesi","a":"Stoma açıklığı su durumuna bağlıdır","d":"Bekçi hücrelerinin turgoru bitkinin genel su durumuyla yakından ilişkilidir. Su yeterliyse stomalar açık, su kıtsa daralma eğilimindedir."},{"t":"İletkenlik ölçümü","a":"Stoma iletkenliği gaz/su geçişini ölçer","d":"Stoma (gözenek) iletkenliği, su buharının yaprak yüzeyinden ne kadar kolay geçtiğini gösteren bir ölçüdür. Stomalar açıkken iletkenlik yüksek, kapalıyken düşüktür."},{"t":"Yorumlama","a":"Düşük iletkenlik su stresi işaretidir","d":"Stoma iletkenliği düştüğünde bu, bitkinin stomaları kapatarak su koruduğu, yani su stresi yaşadığı anlamına gelebilir. Yüksek iletkenlik ise rahat su koşullarını yansıtır."},{"t":"Sonuç","a":"Stoma davranışı su durumunun aynasıdır","d":"Stoma açıklığını ölçmek, bitkinin görünmeyen iç su dengesi hakkında dolaylı ama güvenilir bilgi verir. Bu nedenle tarımda sulama kararlarında kullanılır."}],"ans":"Stoma açıklığı bekçi hücre turgoruna, o da bitkinin su durumuna bağlı olduğundan; düşük gözenek iletkenliği su stresini, yüksek iletkenlik ise rahat su koşullarını yansıtır."},{"q":"Stoma kapanmasının hem su tasarrufu sağladığı hem de bir maliyet doğurduğu durumu, fotosentez ve yaprak sıcaklığı açısından değerlendiriniz.","steps":[{"t":"Su tasarrufu","a":"Kapalı stoma su kaybını engeller","d":"Stomalar kapandığında su buharı çıkışı durur ve bitki suyunu korur. Bu, özellikle kuraklıkta hayatta kalmak için gereklidir."},{"t":"Fotosentez maliyeti","a":"CO2 giremeyince üretim düşer","d":"Ancak kapalı stomadan karbondioksit de giremez, bu yüzden fotosentez hızı azalır ya da durur. Uzun süreli kapanma bitkinin besin üretimini ciddi biçimde sınırlar."},{"t":"Sıcaklık maliyeti","a":"Terleme durunca yaprak ısınır","d":"Terleme yaprağı serinleten bir süreçtir; stomalar kapalıyken bu serinleme ortadan kalkar. Sonuçta yaprak sıcaklığı yükselir ve enzimler zarar görebilir."},{"t":"Sonuç","a":"Tasarruf ile maliyet dengelenmeli","d":"Bitki stomayı kapatarak suyu korurken hem fotosentez kaybını hem de aşırı ısınmayı göze alır. Bu nedenle stoma kapanması ancak gerektiğinde ve ölçülü yapılması gereken bir ödünleşmedir."}],"ans":"Stoma kapanması su tasarrufu sağlar ama CO2 girişini kestiği için fotosentezi düşürür ve terlemeyi durdurarak yaprağın ısınmasına yol açar; bu nedenle tasarruf ile maliyet dengelenmelidir."},{"q":"Aynı bitkide su bol iken ve kuraklık stresi altındayken stoma açıklığının nasıl farklı düzenlendiğini karşılaştırarak açıklayınız.","steps":[{"t":"Su bol durumu","a":"Bekçi hücreleri kolayca turgor kazanır","d":"Su bol olduğunda bekçi hücrelerine yeterli su gider ve turgor rahatça yükselir. Bu koşulda bitki stomalarını geniş açarak bol CO2 alır."},{"t":"Fotosentez önceliği","a":"Su bolken üretim önceliklidir","d":"Su kaybı endişesi az olduğundan bitki fotosentezi en üst düzeye çıkarmayı önceler. Stomalar gün boyu büyük ölçüde açık kalabilir."},{"t":"Kuraklık durumu","a":"ABA hormonu stomayı kapatır","d":"Kuraklıkta üretilen absisik asit (ABA) bekçi hücrelerinden iyon çıkışını tetikleyerek turgoru düşürür. Stomalar daralır veya kapanır."},{"t":"Sonuç","a":"Öncelik su korumaya kayar","d":"Kuraklıkta bitki fotosentezden kısmen ödün vererek suyu korumayı önceler. Böylece su durumuna göre stoma açıklığı esnek biçimde, zıt yönlerde düzenlenir."}],"ans":"Su bolken bekçi hücreleri turgor kazanıp stomalar fotosentez için geniş açılır; kuraklıkta ise ABA hormonu turgoru düşürüp stomaları kapatarak öncelik su korumaya kayar."}]}},"terleme":{"ilkokul":{"kolay":[{"q":"Bitkilerin yapraklarından su buharını dışarı atmasına ne ad verilir?","steps":[{"t":"Su buharı çıkışı","a":"Bitkiden gözle görülmeyen su buharı çıkar","d":"Bitkiler kökleriyle aldıkları suyun bir kısmını yapraklarından su buharı olarak havaya verir. Bu su buharı gözle görülmez ama gerçekten dışarı çıkar."},{"t":"Olayın adı","a":"Bu olaya terleme denir","d":"Bitkinin yapraklarından su buharı atmasına terleme (transpirasyon) adı verilir. Bu, insanların terlemesine benzeyen bir su kaybı olayıdır."}],"ans":"Terleme (transpirasyon) denir."},{"q":"Terleme sırasında su buharı en çok yaprağın hangi yapısından dışarı çıkar?","steps":[{"t":"Yapraktaki açıklıklar","a":"Yaprakta küçük gözenekler vardır","d":"Yaprak yüzeyinde stoma denilen küçük açıklıklar bulunur. Bu açıklıklar hava ile bitki arasında geçiş sağlar."},{"t":"Çıkış yeri","a":"Su buharı stomalardan çıkar","d":"Terleme sırasında su buharı en çok bu stomalardan dışarı atılır. Stomalar açıkken su buharı daha kolay çıkar."}],"ans":"Stomalardan (yapraktaki gözeneklerden) çıkar."},{"q":"Terleme bitkinin hangi yönde su taşımasına yardımcı olur?","steps":[{"t":"Su nereden gelir","a":"Su köklerden alınır","d":"Bitki suyu topraktan kökleriyle alır. Bu suyun yapraklara kadar yukarı çıkması gerekir."},{"t":"Terlemenin yardımı","a":"Terleme suyu yukarı çeker","d":"Yapraklardan su buharı çıkınca, alttan yeni su yukarı çekilir. Böylece terleme suyun kökten yaprağa doğru taşınmasına yardım eder."}],"ans":"Kökten yaprağa (aşağıdan yukarı) su taşınmasına yardımcı olur."},{"q":"Sıcak bir günde bitkinin terlemesi artar mı yoksa azalır mı?","steps":[{"t":"Sıcağın etkisi","a":"Sıcakta su daha çok buharlaşır","d":"Hava sıcak olduğunda sular daha hızlı buharlaşır. Bu durum bitkinin yapraklarındaki su için de geçerlidir."},{"t":"Sonuç","a":"Terleme artar","d":"Sıcak günlerde yapraklardan daha çok su buharlaşır, yani terleme artar. Bu yüzden bitkiler sıcakta daha fazla su kaybeder."}],"ans":"Terleme artar."},{"q":"Bir bitki çok fazla terlerse ve suyu yerine konmazsa ne olur?","steps":[{"t":"Su kaybı","a":"Terlemeyle su azalır","d":"Bitki terleme ile sürekli su kaybeder. Bu suyun yerine kökten yeni su gelmesi gerekir."},{"t":"Sonuç","a":"Bitki solar","d":"Eğer kaybedilen su yerine konmazsa bitki susuz kalır, yaprakları pörsür ve solmaya başlar. Bu yüzden bitkilerin sulanması gerekir."}],"ans":"Bitki susuz kalır ve solar (pörsür)."}],"zor":[{"q":"Bir bitkinin üzerine şeffaf bir poşet geçirilirse poşetin içinde su damlacıkları oluşur, bunun nedeni nedir?","steps":[{"t":"Poşet içinde su buharı","a":"Bitki su buharı verir","d":"Bitki yapraklarından terleme ile su buharı atar. Poşet kapalı olduğu için bu su buharı dışarı kaçamaz ve içeride birikir."},{"t":"Yoğunlaşma","a":"Su buharı poşette toplanır","d":"Poşetin içindeki su buharı miktarı arttıkça poşetin soğuk iç yüzeyinde yoğunlaşır. Buhar tekrar sıvı suya dönüşür."},{"t":"Sonuç","a":"Su damlacıkları görünür","d":"Yoğunlaşan su buharı poşetin içinde damlacıklar olarak görünür. Bu damlacıklar bitkinin terlediğinin kanıtıdır."}],"ans":"Bitki terleme ile su buharı verir, bu buhar poşette yoğunlaşıp su damlacıkları oluşturur."},{"q":"Rüzgârlı bir havada bitkinin terlemesinin artmasının nedeni nedir?","steps":[{"t":"Yaprak çevresindeki nem","a":"Yaprak çevresinde nemli hava birikir","d":"Bitki terlerken yaprağın hemen üstünde nemli bir hava tabakası oluşur. Bu nemli tabaka su buharının çıkışını yavaşlatır."},{"t":"Rüzgârın etkisi","a":"Rüzgâr nemli havayı uzaklaştırır","d":"Rüzgâr estiğinde yaprak çevresindeki nemli hava sürekli uzaklaştırılır ve yerine kuru hava gelir. Kuru hava daha çok su buharı alabilir."},{"t":"Sonuç","a":"Terleme hızlanır","d":"Nemli hava sürekli uzaklaştığı için yapraktan su buharı daha hızlı çıkar. Bu nedenle rüzgârlı havada terleme artar."}],"ans":"Rüzgâr yaprak çevresindeki nemli havayı uzaklaştırdığı için su buharı daha hızlı çıkar ve terleme artar."},{"q":"Yağmurlu ve çok nemli bir havada bitkinin terlemesi neden azalır?","steps":[{"t":"Havadaki nem","a":"Nemli havada zaten çok su buharı vardır","d":"Çok nemli havada zaten bol miktarda su buharı bulunur. Hava neredeyse su buharıyla doludur."},{"t":"Buhar çıkışı","a":"Dolu havaya buhar zor çıkar","d":"Hava su buharıyla doluyken bitkinin yaprağındaki su buharı dışarı çıkmakta zorlanır. Çünkü hava daha fazla nem almak istemez."},{"t":"Sonuç","a":"Terleme azalır","d":"Su buharı kolay çıkamadığı için terleme yavaşlar. Bu nedenle nemli havalarda bitkiler daha az terler."}],"ans":"Hava zaten su buharıyla dolu olduğundan yapraktan buhar çıkışı zorlaşır ve terleme azalır."},{"q":"Yaprakları çok geniş bir bitki ile çok dar yapraklı bir bitki karşılaştırıldığında hangisi genellikle daha çok terler ve neden?","steps":[{"t":"Yüzey alanı","a":"Geniş yaprağın yüzeyi büyüktür","d":"Geniş yapraklı bir bitkinin yüzey alanı, dar yapraklı bitkiye göre çok daha fazladır. Yüzey alanı su buharının çıktığı alanla ilgilidir."},{"t":"Stoma sayısı","a":"Büyük yüzeyde daha çok açıklık olur","d":"Daha geniş yüzeyde genellikle daha çok stoma bulunur ve daha çok alandan su buharlaşır. Dar yaprakta ise hem yüzey hem stoma azdır."},{"t":"Sonuç","a":"Geniş yaprak daha çok terler","d":"Geniş yapraklı bitki daha fazla yüzeyden su buharı attığı için daha çok terler. Bu yüzden kurak yerlerde bitkilerin yaprakları çoğu kez dar ve küçüktür."}],"ans":"Geniş yapraklı bitki daha çok terler; çünkü daha büyük yüzeyden ve daha çok stomadan su buharlaşır."},{"q":"Terleme bitkinin serinlemesine nasıl yardımcı olur?","steps":[{"t":"Su buharlaşması","a":"Sıvı su buhara dönüşürken ısı alır","d":"Yapraktaki sıvı su buhara dönüşürken çevresinden ısı alır. Bu, terimizin buharlaşırken bizi serinletmesine benzer."},{"t":"Yaprağın soğuması","a":"Isı alınınca yaprak serinler","d":"Su buharlaşırken yapraktan ısı çektiği için yaprak biraz serinler. Böylece güneş altında yaprak fazla ısınmaz."},{"t":"Sonuç","a":"Terleme bitkiyi serinletir","d":"Terleme sayesinde bitki sıcak günlerde aşırı ısınmaktan korunur. Yani terleme su taşımanın yanında serinleme de sağlar."}],"ans":"Su buharlaşırken yapraktan ısı çektiği için yaprak serinler; böylece terleme bitkiyi serinletir."}]},"ortaokul":{"kolay":[{"q":"Transpirasyon (terleme) olayı bitkide hangi temel görevi yerine getirir?","steps":[{"t":"Su kaybı","a":"Terleme bir su kaybı olayıdır","d":"Transpirasyon, bitkinin yapraklarından su buharı atmasıdır ve bir miktar su kaybına yol açar. İlk bakışta zararlı görünse de önemli bir işlevi vardır."},{"t":"Su çekimi","a":"Su kaybı yeni su çekilmesini sağlar","d":"Yapraktan su buharı çıkınca altta bir emiş oluşur ve kökten yeni su yukarı çekilir. Böylece su ve minerallerin taşınması sağlanır."},{"t":"Sonuç","a":"Su-mineral taşınması ve serinleme","d":"Terleme hem suyun kökten yaprağa taşınmasını hem de yaprağın serinlemesini sağlar. Yani terleme bitki için yararlı bir süreçtir."}],"ans":"Terleme, kökten yaprağa su ve mineral taşınmasını sağlar ve bitkiyi serinletir."},{"q":"Terlemeyi artıran çevresel etmenlerden üç tanesini sıralayınız.","steps":[{"t":"Buharlaşmayı hızlandıranlar","a":"Bazı koşullar su buharlaşmasını artırır","d":"Terleme aslında bir buharlaşma olayıdır, bu yüzden buharlaşmayı hızlandıran koşullar terlemeyi de artırır. Bu koşulları belirlemek gerekir."},{"t":"Etmenler","a":"Sıcaklık, ışık, rüzgâr ve düşük nem etkilidir","d":"Yüksek sıcaklık, bol ışık ve rüzgâr terlemeyi artırır; düşük hava nemi de buharlaşmayı kolaylaştırır. Bu etmenler stomayı ve buharlaşmayı etkiler."}],"ans":"Yüksek sıcaklık, bol ışık ve rüzgâr (ayrıca düşük nem) terlemeyi artırır."},{"q":"Su buharı çıkışı dışında terlemenin bitki için iki yararını yazınız.","steps":[{"t":"Taşıma yararı","a":"Terleme su ve minerali yukarı taşır","d":"Terleme ile oluşan çekim, topraktan alınan su ve mineralleri yapraklara kadar taşır. Bu, bitkinin beslenmesi için önemlidir."},{"t":"Serinleme yararı","a":"Terleme yaprağı serinletir","d":"Su buharlaşırken yapraktan ısı çekilir ve yaprak serinler. Böylece sıcak günlerde bitki aşırı ısınmadan korunur."}],"ans":"Su ve minerallerin kökten yaprağa taşınmasını sağlar ve yaprağı serinletir."},{"q":"Bitki gövdesinde suyu yapraklara taşıyan iletim borularına ne ad verilir?","steps":[{"t":"İletim sistemi","a":"Bitkide su taşıyan borular vardır","d":"Bitkilerin gövdesinde su ve mineralleri taşıyan özel iletim boruları bulunur. Bunlar bir boru sistemi gibi çalışır."},{"t":"Boruların adı","a":"Bu borulara ksilem denir","d":"Su ve mineralleri kökten yaprağa taşıyan iletim borularına ksilem (odun borusu) adı verilir. Terleme çekimi bu borularda suyu yukarı taşır."}],"ans":"Ksilem (odun borusu) denir."},{"q":"Çok terleyen bir bitkinin yeterince sulanmaması durumunda yapraklarında ne gözlemlenir?","steps":[{"t":"Su dengesi","a":"Kaybedilen su yerine konmalıdır","d":"Bitki terleme ile sürekli su kaybeder ve bu suyun kökten gelen yeni suyla karşılanması gerekir. Sulama yetersizse denge bozulur."},{"t":"Turgor kaybı","a":"Hücreler suyunu kaybeder","d":"Yeterli su gelmeyince yaprak hücreleri turgorunu kaybeder ve gevşer. Dik duran yapraklar artık desteğini yitirir."},{"t":"Sonuç","a":"Yapraklar pörsür ve solar","d":"Turgorunu kaybeden yapraklar pörsür, sarkar ve solmaya başlar. Bu, bitkinin su sıkıntısı çektiğinin açık bir göstergesidir."}],"ans":"Yapraklar turgorunu kaybederek pörsür, sarkar ve solar."}],"zor":[{"q":"Terleme çekimi (kohezyon-gerilim) sayesinde suyun kökten yaprağa çıkışını adım adım açıklayınız.","steps":[{"t":"Su buharı çıkışı","a":"Yapraktan su buharlaşır","d":"Yaprak hücrelerindeki su, stomalardan su buharı olarak dışarı çıkar. Bu, yaprakta su eksikliği yaratır."},{"t":"Çekim oluşması","a":"Eksik su alttaki suyu çeker","d":"Yaprakta su azalınca ksilem borularındaki su sütunu yukarı doğru çekilir. Bu çekime terleme çekimi denir."},{"t":"Su molekülleri tutunması","a":"Su molekülleri birbirine yapışıktır","d":"Su molekülleri birbirine tutunur (kohezyon), bu yüzden çekildiğinde kopmadan bir sütun halinde yukarı hareket eder. Ayrıca boru çeperine de tutunarak (adezyon) destek alır."},{"t":"Sonuç","a":"Su kökten yaprağa kesintisiz çıkar","d":"Yukarıdaki çekim ve molekül tutunması sayesinde su, kökten yaprağa kesintisiz bir sütun halinde taşınır. Böylece bitki pompasız bir şekilde suyu yükseklere ulaştırır."}],"ans":"Yapraktan su buharlaşınca oluşan çekim, kohezyonla birbirine tutunan su sütununu ksilemde kökten yaprağa kesintisiz olarak yukarı taşır."},{"q":"Sıcaklık ve nem terlemeyi neden zıt yönde etkiler, açıklayınız.","steps":[{"t":"Sıcaklığın etkisi","a":"Sıcaklık buharlaşmayı artırır","d":"Sıcaklık yükseldikçe su molekülleri daha hızlı hareket eder ve buharlaşma kolaylaşır. Bu yüzden yüksek sıcaklık terlemeyi artırır."},{"t":"Nemin etkisi","a":"Yüksek nem buharlaşmayı zorlaştırır","d":"Hava nemi yükseldiğinde hava zaten su buharıyla dolar ve yapraktan yeni buhar çıkması zorlaşır. Bu yüzden yüksek nem terlemeyi azaltır."},{"t":"Sonuç","a":"Biri artırır, diğeri azaltır","d":"Sıcaklık arttıkça terleme artar, nem arttıkça terleme azalır; yani bu iki etmen zıt yönde etki gösterir. Bitkinin gerçek terlemesi bu iki etkinin birleşimine bağlıdır."}],"ans":"Sıcaklık buharlaşmayı kolaylaştırıp terlemeyi artırır; yüksek nem ise havayı buharla doldurup buhar çıkışını zorlaştırarak terlemeyi azaltır, bu yüzden zıt yönde etki ederler."},{"q":"Çöl bitkilerinin yapraklarının küçük, dikensi veya mumlu olmasının terleme ile ilişkisini açıklayınız.","steps":[{"t":"Çöl koşulu","a":"Çölde su çok kıttır","d":"Çöllerde su son derece sınırlıdır, bu yüzden bitkilerin su kaybını en aza indirmesi gerekir. Terleme ile fazla su kaybı çöl bitkisi için ölümcül olabilir."},{"t":"Yaprak uyumları","a":"Küçük/mumlu yaprak su kaybını azaltır","d":"Küçük veya dikene dönüşmüş yapraklar daha az yüzeyden su buharı atar. Kalın mumlu kütikula ise su buharının yüzeyden kaçmasını zorlaştırır."},{"t":"Sonuç","a":"Terleme en aza iner","d":"Bu uyumlar sayesinde çöl bitkileri çok az terler ve kıt suyu korur. Böylece kurak ortamda hayatta kalmayı başarırlar."}],"ans":"Küçük, dikensi yapraklar yüzey alanını, mumlu kütikula ise buharlaşmayı azaltarak terlemeyi en aza indirir; böylece çöl bitkileri kıt suyu korur."},{"q":"Bir saksı bitkisinin yapraklarının yarısı koparılırsa terleme miktarı nasıl değişir, nedenini açıklayınız.","steps":[{"t":"Terleme yüzeyi","a":"Yapraklar terlemenin yapıldığı yerdir","d":"Terleme büyük ölçüde yapraklardaki stomalardan gerçekleşir. Yani terleme miktarı yaprak yüzeyi ve stoma sayısıyla doğrudan ilişkilidir."},{"t":"Yaprak azalması","a":"Yaprak azalınca stoma sayısı azalır","d":"Yaprakların yarısı koparıldığında toplam yaprak yüzeyi ve stoma sayısı yaklaşık yarıya iner. Su buharının çıkacağı alan azalır."},{"t":"Sonuç","a":"Terleme azalır","d":"Daha az yüzey ve stoma olduğu için su buharı çıkışı, yani terleme azalır. Bu nedenle nakil sırasında bitkilerin yaprakları budanarak su kaybı düşürülür."}],"ans":"Yaprak yüzeyi ve stoma sayısı azaldığı için terleme miktarı azalır."},{"q":"Terlemenin aşırı olması bitki için neden risk taşır ve bitki bunu nasıl önler?","steps":[{"t":"Aşırı su kaybı","a":"Çok terleme suyu hızla tüketir","d":"Terleme aşırı olursa bitki, kökünden gelebilenden daha hızlı su kaybeder. Bu, hücrelerin susuz kalmasına yol açar."},{"t":"Solma riski","a":"Su dengesi bozulunca bitki solar","d":"Kaybedilen su yerine konamazsa hücreler turgorunu yitirir, yapraklar pörsür ve bitki solar. Aşırı durumda bitki kuruyup ölebilir."},{"t":"Önleme","a":"Bitki stomalarını kapatır","d":"Bitki bu riski önlemek için sıcak ve kurak koşullarda stomalarını kapatarak su buharı çıkışını azaltır. Ayrıca mumlu kütikula gibi yapılarla da su kaybını sınırlar."}],"ans":"Aşırı terleme bitkinin susuz kalıp solmasına yol açabilir; bitki bunu stomalarını kapatarak ve kütikula gibi yapılarla su kaybını sınırlayarak önler."}]},"lise":{"kolay":[{"q":"Transpirasyon (terleme) kavramını ve gerçekleştiği başlıca yolları kısaca açıklayınız.","steps":[{"t":"Tanım","a":"Terleme, bitkiden su buharı kaybıdır","d":"Transpirasyon, bitkinin havadaki yüzeylerinden su buharı kaybetmesidir. Bu olay bitkinin su dengesini ve taşınmasını doğrudan etkiler."},{"t":"Yollar","a":"Stoma, kütikula ve lentisellerden olur","d":"Terlemenin büyük kısmı yapraktaki stomalardan (stomatal terleme) gerçekleşir. Az miktarda kütikuladan (kütikular) ve gövdedeki lentisellerden (lentisel) de su buharı kaybedilir."},{"t":"Önem","a":"Su taşıma ve serinlemeyi sağlar","d":"Terleme, kökten yaprağa su çekilmesini ve yaprağın serinlemesini sağlar. Bu yüzden zorunlu bir su kaybı olarak kabul edilir."}],"ans":"Terleme, bitkiden su buharı kaybıdır; başlıca stomalardan, ayrıca az miktarda kütikula ve lentisellerden gerçekleşir."},{"q":"Terlemenin bitki için sağladığı başlıca yararları sıralayınız.","steps":[{"t":"Su taşıma","a":"Terleme çekimi suyu yukarı taşır","d":"Yapraktan su buharı çıkışı, ksilemde kökten yaprağa doğru su çekimi oluşturur. Bu çekim suyun yükselmesini sağlar."},{"t":"Mineral taşıma","a":"Suyla birlikte mineraller de taşınır","d":"Su yukarı çekilirken topraktan alınan mineraller de suyla birlikte yapraklara ulaşır. Böylece bitkinin beslenmesi desteklenir."},{"t":"Serinleme","a":"Buharlaşma yaprağı serinletir","d":"Su buharlaşırken yapraktan ısı çeker ve yaprağı serinletir. Bu, güneş altında aşırı ısınmayı önler."}],"ans":"Su ve minerallerin kökten yaprağa taşınmasını sağlar ve buharlaşma yoluyla yaprağı serinletir."},{"q":"Terlemeyi etkileyen başlıca çevresel etmenleri ve etki yönlerini açıklayınız.","steps":[{"t":"Artıran etmenler","a":"Sıcaklık, ışık ve rüzgâr terlemeyi artırır","d":"Yüksek sıcaklık ve bol ışık buharlaşmayı ve stoma açıklığını artırarak terlemeyi yükseltir. Rüzgâr da yaprak çevresindeki nemli havayı uzaklaştırarak terlemeyi hızlandırır."},{"t":"Azaltan etmen","a":"Yüksek nem terlemeyi azaltır","d":"Hava nemi arttığında yaprakla hava arasındaki su buharı farkı azalır ve buhar çıkışı zorlaşır. Bu yüzden yüksek nem terlemeyi düşürür."},{"t":"Su durumu","a":"Toprak suyu da belirleyicidir","d":"Toprakta su azaldığında bitki stomalarını kapatarak terlemeyi azaltır. Yani toprak nemi de terleme hızını etkiler."}],"ans":"Sıcaklık, ışık ve rüzgâr terlemeyi artırır; yüksek hava nemi azaltır; toprak suyunun azalması da stoma kapanmasıyla terlemeyi düşürür."},{"q":"Kohezyon-gerilim (terleme çekimi) kuramı suyun yukarı taşınmasını nasıl açıklar?","steps":[{"t":"Gerilim oluşumu","a":"Yapraktan buhar çıkışı gerilim yaratır","d":"Yaprak hücrelerinden su buharlaşınca ksilem su sütununda bir çekme kuvveti (gerilim) oluşur. Bu gerilim suyu yukarı çeken itici güçtür."},{"t":"Kohezyon","a":"Su molekülleri birbirine tutunur","d":"Su molekülleri hidrojen bağlarıyla birbirine tutunur (kohezyon), bu yüzden su sütunu kopmadan tek parça hareket eder. Ayrıca su, ksilem çeperine de tutunur (adezyon)."},{"t":"Sonuç","a":"Kesintisiz su sütunu yükselir","d":"Gerilim ve kohezyon birlikte, kökten yaprağa kadar kesintisiz bir su sütununun yukarı taşınmasını sağlar. Böylece enerji harcamadan su yükseklere ulaşır."}],"ans":"Yapraktan buhar çıkışı ksilemde gerilim oluşturur; kohezyonla birbirine tutunan su molekülleri kesintisiz bir sütun olarak bu gerilimle kökten yaprağa yukarı çekilir."},{"q":"Stomatal terleme ile kütikular terleme arasındaki farkı açıklayınız.","steps":[{"t":"Stomatal terleme","a":"Su buharı stomalardan çıkar","d":"Terlemenin büyük çoğunluğu yapraktaki stomalardan gerçekleşir ve bitki bu yolu stomaları açıp kapatarak kontrol edebilir. Bu, denetlenebilir bir su kaybıdır."},{"t":"Kütikular terleme","a":"Su buharı kütikuladan sızar","d":"Yaprak yüzeyini örten mumsu kütikula tabakasından da az miktarda su buharı geçer. Bu yol denetlenemez ve genellikle toplam terlemenin küçük bir kısmıdır."},{"t":"Sonuç","a":"Biri kontrol edilebilir, diğeri sızıntıdır","d":"Stomatal terleme bitkinin ayarlayabildiği ana yoldur; kütikular terleme ise kütikulanın kalınlığına bağlı sabit bir sızıntıdır. Kalın kütikula kütikular terlemeyi azaltır."}],"ans":"Stomatal terleme stomalardan olur ve kontrol edilebilir, toplamın çoğunu oluşturur; kütikular terleme kütikuladan sızan, kontrol edilemeyen küçük bir su kaybıdır."},{"q":"Terleme ile gutasyon (su damlacığı salgısı) arasındaki temel farkı açıklayınız.","steps":[{"t":"Terleme","a":"Terleme su buharı kaybıdır","d":"Terleme, bitkiden su buharı (gaz halinde su) kaybedilmesidir ve genellikle gündüz, stomalar açıkken artar. Kaybedilen su gözle görülmez."},{"t":"Gutasyon","a":"Gutasyon sıvı su damlacığıdır","d":"Gutasyon ise yaprak kenarlarındaki özel açıklıklardan (hidatot) sıvı halde su damlacıklarının dışarı verilmesidir. Çoğunlukla gece veya nemli sabahlarda, terleme düşükken görülür."},{"t":"Sonuç","a":"Hal ve koşullar farklıdır","d":"Terleme buhar, gutasyon sıvı su kaybıdır; biri kuru-sıcak koşullarda artarken diğeri nemli-serin koşullarda görülür. Bu yüzden iki olay birbirinden ayrılır."}],"ans":"Terleme su buharı (gaz) kaybıdır ve gündüz artar; gutasyon ise hidatotlardan sıvı su damlacığı salgılanmasıdır ve nemli/serin koşullarda görülür."},{"q":"Bir bitkide terleme ile su ve mineral taşınması arasındaki bağlantıyı açıklayınız.","steps":[{"t":"Çekim oluşumu","a":"Terleme yukarı doğru çekim yaratır","d":"Yapraktan su buharı çıktığında ksilemde kökten yaprağa doğru bir çekim oluşur. Bu çekim suyu yukarı taşıyan asıl kuvvettir."},{"t":"Minerallerin taşınması","a":"Su minerali de beraberinde taşır","d":"Topraktan kök tarafından alınan mineraller suda çözünmüş halde bulunur ve su yukarı çekilirken minerallerle birlikte taşınır. Böylece mineraller yapraklara ulaşır."},{"t":"Sonuç","a":"Terleme beslenmeyi destekler","d":"Terleme ne kadar düzenli olursa su ve mineral taşınması da o kadar etkili olur. Bu nedenle terleme, bitkinin beslenmesine dolaylı olarak katkı sağlar."}],"ans":"Terleme ksilemde su çekimi oluşturur; bu çekim suda çözünmüş mineralleri de kökten yaprağa taşıyarak bitkinin beslenmesini destekler."},{"q":"Terlemenin yaprak sıcaklığını düşürmedeki rolünü açıklayınız.","steps":[{"t":"Buharlaşma ısısı","a":"Su buharlaşırken ısı alır","d":"Sıvı suyun buhara dönüşmesi enerji (ısı) gerektirir ve bu ısı yapraktan çekilir. Buna buharlaşma gizli ısısı denir."},{"t":"Yaprağın soğuması","a":"Isı çekilince yaprak serinler","d":"Su buharlaşırken yaprağın yüzeyinden ısı çekildiği için yaprak sıcaklığı düşer. Bu, güneş altında yaprağın aşırı ısınmasını engeller."},{"t":"Sonuç","a":"Enzimler korunur","d":"Yaprağın serin kalması, fotosentez ve diğer enzimlerin uygun sıcaklıkta çalışmasını sağlar. Böylece terleme, bitkinin işlevlerini korumasına yardımcı olur."}],"ans":"Su buharlaşırken yapraktan ısı (buharlaşma gizli ısısı) çekildiği için yaprak serinler; bu da enzimleri ve fotosentezi aşırı ısınmadan korur."},{"q":"Rüzgârın terleme üzerindeki etkisini, yaprak çevresindeki sınır tabakası kavramıyla açıklayınız.","steps":[{"t":"Sınır tabakası","a":"Yaprak çevresinde durgun nemli hava vardır","d":"Yaprağın hemen yüzeyinde, sınır tabakası denilen ince ve durgun bir nemli hava katmanı bulunur. Bu tabaka su buharının çıkışını yavaşlatır."},{"t":"Rüzgârın etkisi","a":"Rüzgâr sınır tabakasını inceltir","d":"Rüzgâr estiğinde bu nemli sınır tabakası uzaklaştırılır veya inceltilir ve yerine kuru hava gelir. Kuru hava daha fazla su buharı alabilir."},{"t":"Sonuç","a":"Terleme artar","d":"Sınır tabakası inceldikçe su buharı yapraktan daha kolay kaçar ve terleme artar. Çok şiddetli rüzgârda ise stomalar kapanarak terleme yeniden sınırlanabilir."}],"ans":"Rüzgâr yaprak çevresindeki nemli sınır tabakasını inceltip uzaklaştırdığı için su buharı daha kolay çıkar ve terleme artar."},{"q":"Işığın terlemeyi artırmasının nedenini stomalar üzerinden açıklayınız.","steps":[{"t":"Işık ve stoma","a":"Işık stomaları açar","d":"Işık, bekçi hücrelerini uyararak stomaların açılmasını sağlar; çünkü gündüz fotosentez için karbondioksit alımı gerekir. Açık stoma su buharı çıkışına da izin verir."},{"t":"Açık stoma","a":"Açık stomadan su buharı çıkar","d":"Stomalar açıkken yaprağın içinden su buharı dışarı kolayca çıkar. Bu nedenle stoma açıklığı terleme hızını doğrudan etkiler."},{"t":"Sonuç","a":"Işıkta terleme artar","d":"Işık stomaları açtığı için gündüz terleme gece terlemesinden fazladır. Ayrıca ışık yaprağı ısıtarak buharlaşmayı da hızlandırır."}],"ans":"Işık bekçi hücrelerini uyarıp stomaları açtığından su buharı çıkışı kolaylaşır; bu yüzden ışıkta (gündüz) terleme artar."},{"q":"Ksilemde suyun kohezyonu ve adezyonu terleme çekiminde hangi rolleri üstlenir?","steps":[{"t":"Kohezyon","a":"Su molekülleri birbirine tutunur","d":"Su molekülleri arasındaki hidrojen bağları kohezyonu sağlar ve su sütununun kopmadan bütün kalmasını mümkün kılar. Bu, çekim altında sütunun parçalanmamasını sağlar."},{"t":"Adezyon","a":"Su, ksilem çeperine tutunur","d":"Su molekülleri ksilem borularının çeperine de tutunur (adezyon); bu, su sütununun aşağı kaymasını engeller ve yukarı çekimi destekler. Özellikle ince borularda bu etki güçlüdür."},{"t":"Sonuç","a":"İki kuvvet su sütununu ayakta tutar","d":"Kohezyon su sütununu bütün tutar, adezyon ise çepere tutundurarak destekler; ikisi birlikte terleme çekimiyle suyun kesintisiz yükselmesini sağlar. Bu sayede bitki uzun mesafelere su taşıyabilir."}],"ans":"Kohezyon su sütununu kopmadan bütün tutar, adezyon ise suyu ksilem çeperine tutundurarak destekler; ikisi birlikte terleme çekimiyle suyun kesintisiz yükselmesini sağlar."},{"q":"Geniş yapraklı bir bitkinin terleme hızının yüksek olması ile yaprak yüzey alanı arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Yüzey ve stoma","a":"Geniş yaprakta çok stoma bulunur","d":"Geniş yapraklı bir bitkinin yüzey alanı büyük olduğundan üzerinde daha çok stoma yer alır. Stoma sayısı terleme yüzeyiyle doğrudan ilgilidir."},{"t":"Buharlaşma alanı","a":"Büyük yüzey daha çok su buharlaştırır","d":"Daha büyük yaprak yüzeyi, su buharının çıkabileceği daha geniş bir alan demektir. Bu da daha çok su kaybı anlamına gelir."},{"t":"Sonuç","a":"Terleme hızı yüksektir","d":"Geniş yapraklı bitkiler büyük yüzeyleri ve çok stomaları nedeniyle hızlı terler. Bu yüzden bu bitkiler genellikle suyun bol olduğu nemli ortamlarda yetişir."}],"ans":"Geniş yaprak yüzeyi daha fazla stoma ve daha büyük buharlaşma alanı sağladığından terleme hızı yüksek olur; bu nedenle geniş yapraklı bitkiler çoğunlukla nemli ortamlarda yaşar."},{"q":"Terlemenin gün içinde değişen hızını (gündüz yüksek, gece düşük) stomaların durumuyla ilişkilendirerek açıklayınız.","steps":[{"t":"Gündüz durumu","a":"Gündüz stomalar açıktır","d":"Gündüz ışık ve fotosentez ihtiyacı nedeniyle stomalar açıktır ve karbondioksit alınır. Açık stomadan su buharı da bol miktarda çıkar."},{"t":"Gece durumu","a":"Gece stomalar kapanır","d":"Gece çoğu bitkide stomalar kapanır çünkü fotosentez durur ve karbondioksite ihtiyaç azalır. Kapalı stomadan su buharı çıkışı büyük ölçüde durur."},{"t":"Sonuç","a":"Terleme gündüz yüksek, gece düşüktür","d":"Stomalar gündüz açık, gece kapalı olduğu için terleme gündüz yüksek, gece düşüktür. Ayrıca gündüz sıcaklık ve ışık da terlemeyi artırır."}],"ans":"Gündüz stomalar açık olduğundan terleme yüksek, gece stomalar kapandığından terleme düşüktür; gündüzün sıcaklık ve ışığı da bu farkı pekiştirir."},{"q":"Toprak suyunun azalmasının terlemeyi ve dolayısıyla su taşınmasını nasıl etkilediğini açıklayınız.","steps":[{"t":"Su azlığı","a":"Toprakta su azalır","d":"Toprakta su azaldığında kökler yeterince su alamaz ve bitkinin su dengesi bozulmaya başlar. Bu durum yapraklara da yansır."},{"t":"Stoma tepkisi","a":"Bitki stomalarını kapatır","d":"Su sıkıntısında bitki absisik asit hormonu üreterek stomalarını kapatır ve terlemeyi azaltır. Bu, suyu korumak için bir tedbirdir."},{"t":"Sonuç","a":"Su taşınması yavaşlar","d":"Stomalar kapanınca terleme çekimi azalır ve kökten yaprağa su-mineral taşınması da yavaşlar. Böylece su tasarrufu sağlanırken fotosentez ve beslenme kısıtlanır."}],"ans":"Toprak suyu azalınca bitki ABA ile stomaları kapatıp terlemeyi düşürür; bu da terleme çekimini ve kökten yaprağa su-mineral taşınmasını yavaşlatır."},{"q":"Terlemenin bitki için hem yararlı hem de riskli bir süreç olmasını açıklayınız.","steps":[{"t":"Yararları","a":"Su taşıma ve serinleme sağlar","d":"Terleme, kökten yaprağa su ve mineral taşınmasını sağlar ve buharlaşmayla yaprağı serinletir. Bu yönüyle bitki için yararlı ve gereklidir."},{"t":"Riski","a":"Aşırı terleme su kaybına yol açar","d":"Terleme çok fazla olursa bitki kökünden gelebilenden hızlı su kaybeder ve susuz kalabilir. Bu da solmaya ve hatta kurumaya yol açabilir."},{"t":"Sonuç","a":"Denge gereklidir","d":"Bitki terlemenin yararından faydalanırken aşırı su kaybı riskini de yönetmek zorundadır. Bunu stoma kontrolü ve yapısal uyumlarla dengeler."}],"ans":"Terleme su-mineral taşınması ve serinleme sağlayarak yararlıdır; ancak aşırı olursa susuz kalma ve solma riski doğurur, bu yüzden stoma kontrolüyle dengelenmesi gerekir."}],"zor":[{"q":"Kohezyon-gerilim kuramında suyun ksilemde negatif basınç (gerilim) altında taşınmasını ve kavitasyon riskini açıklayınız.","steps":[{"t":"Negatif basınç","a":"Su sütunu gerilim altındadır","d":"Terleme yapraktan su çekerken ksilemdeki su sütunu pozitif değil, negatif basınç (gerilim) altında bulunur. Yani su yukarıdan çekilir, alttan itilmez."},{"t":"Kohezyonun rolü","a":"Kohezyon sütunu bütün tutar","d":"Su moleküllerinin hidrojen bağlarıyla birbirine tutunması (kohezyon), gerilim altındaki sütunun kopmadan kalmasını sağlar. Bu sayede yüksek gerilim bile taşınabilir."},{"t":"Kavitasyon riski","a":"Gerilim çok artarsa hava kabarcığı oluşur","d":"Gerilim aşırı yükselir veya sütun bozulursa içeride hava kabarcığı (kavitasyon/embolizm) oluşabilir ve su iletimi kesilir. Bu, susuzlukta ciddi bir tehlikedir."},{"t":"Sonuç","a":"Bitki kavitasyonu önlemeye çalışır","d":"Bitki, ksilem yapısı ve stoma kontrolüyle gerilimi belli sınırda tutarak kavitasyonu önlemeye çalışır. Oluşan embolizmleri ise bazı yapılarla kısmen onarabilir."}],"ans":"Terleme ksilemde negatif basınç (gerilim) oluşturur, kohezyon sütunu bütün tutar; gerilim aşırı artarsa hava kabarcığı (kavitasyon) oluşup iletim kesilebilir, bu yüzden bitki stoma kontrolüyle gerilimi sınırlar."},{"q":"Su potansiyeli kavramını kullanarak suyun topraktan kök, gövde ve yaprak yoluyla atmosfere kadar nasıl ilerlediğini açıklayınız.","steps":[{"t":"Su potansiyeli gradyanı","a":"Su yüksek potansiyelden düşüğe akar","d":"Su, daima su potansiyelinin yüksek olduğu yerden düşük olduğu yere doğru hareket eder. Bitkide bu gradyan topraktan atmosfere doğru azalır."},{"t":"Toprak-kök-gövde","a":"Toprakta yüksek, yaprakta düşüktür","d":"Toprak suyunun potansiyeli en yüksek, kök ve gövde orta düzeyde, yaprak ise daha düşüktür. Bu yüzden su topraktan köke, oradan gövdeye ve yaprağa ilerler."},{"t":"Atmosfer","a":"Atmosferin su potansiyeli en düşüktür","d":"Kuru atmosferin su potansiyeli çok düşük (çok negatif) olduğundan yapraktaki su buhar olarak atmosfere çekilir. Bu en büyük potansiyel farkıdır."},{"t":"Sonuç","a":"Süreklilik halinde su taşınır","d":"Topraktan atmosfere doğru azalan su potansiyeli gradyanı, suyu kesintisiz bir akış halinde yukarı taşır. Bu sürekli sisteme toprak-bitki-atmosfer sürekliliği denir."}],"ans":"Su potansiyeli topraktan atmosfere doğru azalır; su daima yüksekten düşük potansiyele aktığından bu gradyan suyu topraktan kök, gövde ve yaprak yoluyla atmosfere kesintisiz taşır."},{"q":"Bir bitkide kök basıncı ile terleme çekiminin su taşınmasındaki rollerini karşılaştırınız.","steps":[{"t":"Kök basıncı","a":"Kök suyu aşağıdan iter","d":"Kök hücrelerine mineral birikmesiyle osmozla su girer ve ksilemde pozitif bir basınç (kök basıncı) oluşur. Bu basınç suyu aşağıdan yukarı iter."},{"t":"Sınırı","a":"Kök basıncı zayıf ve sınırlıdır","d":"Kök basıncı genellikle zayıftır ve suyu ancak kısa boylu bitkilerde, terlemenin düşük olduğu gece veya nemli koşullarda yukarı itebilir. Yüksek ağaçlarda yetersiz kalır."},{"t":"Terleme çekimi","a":"Çekim suyu yukarıdan çeker","d":"Terleme çekimi ise yapraktan oluşan gerilimle suyu yukarıdan çeker ve çok güçlüdür. Uzun ağaçlarda suyu tepelere kadar bu çekim taşır."},{"t":"Sonuç","a":"Terleme çekimi baskın mekanizmadır","d":"Kök basıncı yardımcı ve sınırlı bir mekanizma iken, terleme çekimi su taşınmasının asıl ve baskın gücüdür. Çoğu bitkide su büyük ölçüde terleme çekimiyle yükselir."}],"ans":"Kök basıncı suyu zayıfça aşağıdan iter ve sadece kısa bitkilerde/gece etkilidir; terleme çekimi ise suyu güçlü gerilimle yukarıdan çeker ve su taşınmasının baskın mekanizmasıdır."},{"q":"Kurak ortam bitkilerinin (kserofit) terlemeyi azaltmaya yönelik yapısal uyumlarını çok yönlü olarak açıklayınız.","steps":[{"t":"Yüzey azaltma","a":"Yapraklar küçük veya dikenseldir","d":"Kserofitlerde yapraklar küçülmüş, kıvrılmış veya dikene dönüşmüştür; böylece su buharının çıktığı yüzey alanı azalır. Bazılarında fotosentez gövdeye kaymıştır."},{"t":"Kütikula ve tüy","a":"Kalın mum tabakası ve tüyler bulunur","d":"Kalın mumsu kütikula buharlaşmayı zorlaştırır, yaprak yüzeyindeki tüyler ise nemli durgun hava tutarak terlemeyi azaltır. Bu yapılar su kaybını önemli ölçüde sınırlar."},{"t":"Gömülü stoma","a":"Stomalar çukurlara gömülüdür","d":"Stomaların yüzey altındaki çukurlara gömülmesi, çevrelerinde nemli durgun hava oluşturarak su buharı çıkışını yavaşlatır. Stoma sayısının az olması da etkilidir."},{"t":"Sonuç","a":"Su kaybı en aza iner","d":"Bu uyumların birleşimi kserofitlerin çok az terlemesini ve kıt suyu uzun süre korumasını sağlar. Böylece kurak ortamlarda hayatta kalabilirler."}],"ans":"Kserofitlerde küçük/dikensi yapraklar, kalın mumlu kütikula, yüzey tüyleri ve gömülü-az sayıda stoma birlikte buharlaşma yüzeyini ve hızını azaltarak terlemeyi en aza indirir, böylece kıt su korunur."},{"q":"Terleme hızının yüksek olduğu öğle saatlerinde bazı bitkilerde stomaların kısmen kapanmasının (midday closure) nedenini ve sonucunu açıklayınız.","steps":[{"t":"Öğle koşulu","a":"Öğle sıcağında terleme zirveye çıkar","d":"Öğle saatlerinde sıcaklık ve ışık en yüksek düzeydedir, bu yüzden terleme hızı zirveye ulaşır. Su kaybı kökün karşılayabileceğinden fazla olabilir."},{"t":"Su açığı","a":"Su kaybı su alımını geçer","d":"Terleme, kökten gelen su alımını aştığında yaprak hücrelerinde geçici bir su açığı oluşur. Bekçi hücreleri turgorunu kaybetmeye başlar."},{"t":"Kısmi kapanma","a":"Stomalar bir süre kapanır","d":"Su açığını gidermek için bitki öğle saatlerinde stomalarını kısmen kapatır ve terlemeyi azaltır. Bu davranışa öğle kapanması (midday closure) denir."},{"t":"Sonuç","a":"Su korunur ama fotosentez düşer","d":"Öğle kapanması su kaybını sınırlar ve solmayı önler, ancak bu süre boyunca karbondioksit girişi azaldığından fotosentez geçici olarak düşer. Bu, su koruma ile üretim arasında bir ödünleşmedir."}],"ans":"Öğle sıcağında terleme su alımını aşıp su açığı yarattığı için bitki stomalarını kısmen kapatır; bu su kaybını sınırlar ve solmayı önler, ancak fotosentez geçici olarak düşer."},{"q":"Bir potometre düzeneğiyle terleme hızının ölçülmesinin mantığını ve sınırlılığını açıklayınız.","steps":[{"t":"Düzenek mantığı","a":"Potometre su alımını ölçer","d":"Potometre, kesilmiş bir sürgünün su dolu bir sistemde ne kadar su çektiğini ölçen bir düzenektir. Bir hava kabarcığının ya da su seviyesinin hareketi su alımını gösterir."},{"t":"Su alımı-terleme ilişkisi","a":"Su alımı terlemeyi yaklaşık yansıtır","d":"Bitki kaybettiği suyu yerine koymak için su çektiğinden, çekilen su miktarı terlemeye yaklaşık olarak eşittir. Böylece potometre dolaylı olarak terleme hızını verir."},{"t":"Sınırlılık","a":"Su alımı terlemeye tam eşit değildir","d":"Çekilen suyun bir kısmı fotosentezde ve hücre büyümesinde kullanılır, ayrıca hücrelerde depolanabilir; bu yüzden su alımı terlemeden biraz farklı olabilir. Bu nedenle potometre terlemeyi yaklaşık ölçer."},{"t":"Sonuç","a":"İyi bir göreli ölçüm aracıdır","d":"Potometre mutlak terlemeyi tam vermese de, farklı koşulların (ışık, rüzgâr, nem) terlemeyi nasıl etkilediğini karşılaştırmak için kullanışlıdır. Bu yüzden deneylerde göreli karşılaştırma aracı olarak tercih edilir."}],"ans":"Potometre, bitkinin kaybettiği suyu yerine koyma çabasını (su alımını) ölçerek terlemeyi dolaylı yansıtır; ancak alınan suyun bir kısmı fotosentez ve depolamada kullanıldığından ölçüm yaklaşıktır, daha çok göreli karşılaştırma için uygundur."},{"q":"Hidatotlardan gerçekleşen gutasyonun terleme düşükken (gece/nemli sabah) ortaya çıkmasını kök basıncı ile ilişkilendirerek açıklayınız.","steps":[{"t":"Düşük terleme","a":"Gece terleme neredeyse durur","d":"Geceleri stomalar kapalı ve hava nemli olduğundan terleme çok düşüktür. Bu yüzden suyu yukarı çeken terleme çekimi neredeyse yoktur."},{"t":"Kök basıncı baskınlaşır","a":"Su alımı sürerken çekim olmaz","d":"Kökler mineral alıp osmozla su çekmeye devam eder ve ksilemde kök basıncı oluşur. Terleme çekimi olmadığından bu basınç suyu yukarı itmeye devam eder."},{"t":"Sıvı su çıkışı","a":"Fazla su hidatotlardan damlar","d":"Kök basıncıyla yukarı itilen fazla su, terleme ile buharlaşamadığından yaprak kenarındaki hidatotlardan sıvı damlacıklar halinde dışarı verilir. Buna gutasyon denir."},{"t":"Sonuç","a":"Gutasyon su fazlasının atılmasıdır","d":"Gutasyon, terlemenin düşük olduğu koşullarda kök basıncının ittiği fazla suyun sıvı halde atılmasıdır. Bu yüzden çoğunlukla serin ve nemli gecelerde/sabahlarda görülür."}],"ans":"Gece terleme durduğundan çekim yoktur; kökler su çekmeyi sürdürdüğü için kök basıncı oluşur ve fazla su, buharlaşamadığından hidatotlardan sıvı damlacıklar (gutasyon) halinde atılır."},{"q":"Terlemenin mineral taşınmasındaki rolünün, mineral alımının aktif olduğu gerçeğiyle nasıl bağdaştığını açıklayınız.","steps":[{"t":"Mineral alımı","a":"Kökte mineral alımı aktiftir","d":"Minerallerin topraktan kök hücrelerine alınması genellikle enerji harcayan aktif taşıma ile olur ve terlemeden bağımsızdır. Yani terleme olmasa da kök mineral alabilir."},{"t":"Taşıma aşaması","a":"Alınan mineral ksilemle yukarı taşınır","d":"Kökte ksileme verilen mineraller, su akışıyla birlikte yapraklara taşınır. İşte bu yukarı taşıma aşamasında terleme çekimi önemli rol oynar."},{"t":"Terlemenin katkısı","a":"Terleme taşıma hızını artırır","d":"Terleme çekimi su akışını hızlandırdığında, suda çözünmüş minerallerin yapraklara taşınması da hızlanır. Yani terleme alımı değil, dağıtımı destekler."},{"t":"Sonuç","a":"Alım aktif, taşıma terlemeye bağlıdır","d":"Mineral alımı esas olarak aktif taşımayla gerçekleşirken, alınan minerallerin yapraklara dağıtımı terleme çekiminden yararlanır. Bu iki süreç birbirini tamamlar; terleme alımı değil taşımayı kolaylaştırır."}],"ans":"Mineral alımı kökte enerji harcayan aktif taşımayla olur ve terlemeden bağımsızdır; ancak alınan minerallerin ksilemle yapraklara taşınmasını terleme çekimi hızlandırır, yani terleme alımı değil dağıtımı destekler."},{"q":"Aynı bitkide nemli ve kuru ortamlarda terleme hızının nasıl farklılaştığını, buhar basıncı farkı kavramıyla açıklayınız.","steps":[{"t":"Buhar basıncı farkı","a":"Terleme yaprak-hava buhar farkına bağlıdır","d":"Terleme hızı, yaprak içindeki su buharı basıncı ile dış havadaki su buharı basıncı arasındaki farka bağlıdır. Fark büyüdükçe buhar daha hızlı dışarı çıkar."},{"t":"Nemli ortam","a":"Nemde fark küçülür","d":"Nemli ortamda havanın buhar basıncı yüksektir, bu yüzden yaprak ile hava arasındaki fark küçülür. Küçük fark, su buharının yavaş çıkmasına yol açar."},{"t":"Kuru ortam","a":"Kuruda fark büyür","d":"Kuru ortamda havanın buhar basıncı düşüktür, dolayısıyla yaprak ile hava arasındaki fark büyür. Büyük fark su buharını hızla dışarı çeker."},{"t":"Sonuç","a":"Kuruda terleme daha hızlıdır","d":"Bu nedenle aynı bitki kuru ortamda nemli ortama göre çok daha hızlı terler. Buhar basıncı farkı, terlemenin temel itici gücüdür."}],"ans":"Terleme yaprak ile hava arasındaki buhar basıncı farkına bağlıdır; nemli ortamda bu fark küçülüp terleme yavaşlar, kuru ortamda fark büyüyüp terleme hızlanır."},{"q":"Yaprak dökümünün (örneğin sonbaharda) terleme ve su dengesi açısından bitkiye sağladığı avantajı açıklayınız.","steps":[{"t":"Soğuk dönem","a":"Kışın su alımı zorlaşır","d":"Soğuk veya donlu dönemlerde toprak suyu donabilir ya da kökler suyu yeterince alamaz. Bu durumda su alımı ciddi biçimde kısıtlanır."},{"t":"Terleme riski","a":"Yapraklar terlemeyi sürdürür","d":"Yapraklar bitki üzerinde kalırsa terleme ile su kaybı sürer; ancak alım azaldığından bitki susuz kalma tehlikesiyle karşılaşır. Bu, kuraklık benzeri bir su açığı yaratır."},{"t":"Yaprak dökümü","a":"Bitki yapraklarını döker","d":"Bitki sonbaharda yapraklarını dökerek terleme yüzeyini neredeyse ortadan kaldırır. Böylece su kaybı en aza iner."},{"t":"Sonuç","a":"Su dengesi korunur","d":"Yaprak dökümü sayesinde bitki, su alımının zor olduğu dönemde aşırı su kaybından korunur ve su dengesini sürdürür. Bu, soğuk ve kurak mevsimlere karşı bir uyumdur."}],"ans":"Soğuk dönemde su alımı zorlaşırken yapraklar terlemeyi sürdürüp su açığı yaratır; bitki yapraklarını dökerek terleme yüzeyini ortadan kaldırır ve aşırı su kaybından korunarak su dengesini korur."},{"q":"Stoma açıklığı ile terleme hızı arasındaki ilişkinin doğrusal olmamasını (küçük açıklıkta bile yüksek terleme) sınır tabakası ve kenar etkisiyle açıklayınız.","steps":[{"t":"Beklenti","a":"Açıklıkla terleme doğru orantılı sanılır","d":"İlk bakışta stoma ne kadar açıksa terlemenin de o oranda artması beklenir. Ancak gerçekte ilişki tam doğrusal değildir."},{"t":"Kenar etkisi","a":"Küçük açıklıkta kenarlardan hızlı difüzyon olur","d":"Küçük bir gözenekte su buharı molekülleri açıklığın kenarlarından dışa doğru yelpaze gibi yayılır ve birim alana göre çok verimli difüzyon olur. Bu kenar (edge) etkisi, küçük açıklıkta bile yüksek terleme sağlar."},{"t":"Büyük açıklık","a":"Açıklık büyüyünce kenar etkisi azalır","d":"Stoma iyice açıldığında merkez bölgesi artar ama kenar etkisinin katkısı oransal olarak azalır. Ayrıca yaprak çevresindeki sınır tabakası difüzyonu sınırlamaya başlar."},{"t":"Sonuç","a":"İlişki doyma eğilimi gösterir","d":"Bu yüzden stoma yarı açıkken bile terleme tam açık duruma yakın olabilir ve açıklık arttıkça terleme artışı yavaşlar. İlişki doyma (plato) eğrisi şeklindedir, doğrusal değildir."}],"ans":"Küçük gözenekte kenarlardan verimli difüzyon (kenar etkisi) olduğundan az açıklıkta bile terleme yüksektir; açıklık büyüdükçe kenar etkisi ve sınır tabakası nedeniyle artış yavaşlar, böylece ilişki doğrusal değil doyma eğrisi şeklindedir."},{"q":"Bir ağacın tepesindeki yapraklara su ulaşmasının fiziksel olarak nasıl mümkün olduğunu, terleme çekimi ve su sütununun gerilim dayanımıyla açıklayınız.","steps":[{"t":"Yükseklik sorunu","a":"Yüksek ağaçlara su pompasız çıkmalı","d":"Çok yüksek ağaçlarda suyun tepelere kadar çıkması gerekir, ancak bitkide kalp gibi bir pompa yoktur. Bu durum fiziksel bir zorluk gibi görünür."},{"t":"Terleme çekimi","a":"Tepedeki yapraklar suyu yukarı çeker","d":"Tepedeki yapraklardan gerçekleşen terleme güçlü bir gerilim oluşturur ve bu gerilim su sütununu yukarı çeker. Çekim yukarıdan geldiği için yüksekliğe rağmen su yükselebilir."},{"t":"Gerilim dayanımı","a":"Kohezyon su sütununu kopmadan tutar","d":"Su moleküllerinin güçlü kohezyonu, yüksek gerilim altında bile su sütununun kopmadan bütün kalmasını sağlar. İnce ksilem boruları ve adezyon da bu dayanımı destekler."},{"t":"Sonuç","a":"Su tepelere kesintisiz ulaşır","d":"Terleme çekimi ile oluşan gerilim ve su sütununun kohezyon sayesinde yüksek gerilime dayanması birlikte, suyu en yüksek ağaçların tepesine kadar pompasız taşır. Bu, kohezyon-gerilim kuramının en çarpıcı sonucudur."}],"ans":"Tepedeki yapraklardan gelen terleme çekimi güçlü bir gerilim oluşturur; su moleküllerinin kohezyonu bu yüksek gerilime dayanıp sütunu bütün tuttuğundan su, pompa olmadan en yüksek ağaçların tepesine kadar kesintisiz taşınır."},{"q":"Terleme ile su kaybı arasındaki ödünleşmeyi azaltmak için bitkilerde görülen C4 ve CAM gibi fizyolojik uyumların terlemeyle ilişkisini açıklayınız.","steps":[{"t":"Temel ödünleşme","a":"CO2 almak su kaybı gerektirir","d":"Fotosentez için stoma açıp CO2 almak, kaçınılmaz olarak su buharı kaybına yol açar. Sıcak-kurak ortamlarda bu su kaybı çok yüksek olabilir."},{"t":"C4 uyumu","a":"C4 bitkileri CO2yi verimli kullanır","d":"C4 bitkileri karbondioksiti özel hücrelerde yoğunlaştırarak düşük stoma açıklığında bile yeterli CO2 sağlar. Böylece daha az stoma açıklığıyla, yani daha az su kaybıyla fotosentez yapar."},{"t":"CAM uyumu","a":"CAM bitkileri stomayı gece açar","d":"CAM bitkileri gündüz stomalarını kapalı tutup geceleri açarak CO2 alır ve depolar. Serin gecede terleme düşük olduğundan aynı CO2 için çok daha az su kaybedilir."},{"t":"Sonuç","a":"Su kullanım verimi artar","d":"C4 ve CAM uyumları, alınan CO2 başına kaybedilen su miktarını azaltarak su kullanım verimini yükseltir. Bu sayede bu bitkiler sıcak ve kurak ortamlarda az suyla fotosentezi sürdürebilir."}],"ans":"C4 bitkileri CO2yi yoğunlaştırıp düşük stoma açıklığıyla fotosentez yaparak, CAM bitkileri ise stomayı serin gecede açıp gündüz kapatarak su kaybını azaltır; her ikisi de alınan CO2 başına su kaybını düşürerek su kullanım verimini artırır."},{"q":"Aşırı terlemeye karşı bitkinin geliştirdiği kısa süreli (fizyolojik) ve uzun süreli (yapısal) savunmaları karşılaştırınız.","steps":[{"t":"Kısa süreli savunma","a":"Stoma kapanması hızlı tepkidir","d":"Bitki aşırı su kaybı algıladığında saniyeler-dakikalar içinde absisik asit aracılığıyla stomalarını kapatır. Bu hızlı, geri dönüşümlü bir fizyolojik tepkidir."},{"t":"Yaprak hareketi","a":"Yaprak kıvrılması da geçici tepkidir","d":"Bazı bitkiler su açığında yapraklarını kıvırarak ya da sarkıtarak güneşe ve havaya açık yüzeyi azaltır. Bu da kısa sürede tersine çevrilebilen bir tepkidir."},{"t":"Uzun süreli savunma","a":"Yapısal uyumlar kalıcıdır","d":"Sürekli kuraklığa maruz bitkiler kalın kütikula, gömülü stoma, küçük/tüylü yaprak gibi kalıcı yapısal uyumlar geliştirir. Bunlar gelişim sırasında oluşur ve uzun vadeli su tasarrufu sağlar."},{"t":"Sonuç","a":"İki düzey birlikte korur","d":"Kısa süreli tepkiler ani su açıklarını hızla yönetirken, uzun süreli uyumlar bitkiyi kurak ortama kalıcı olarak hazırlar. Bu iki düzey birlikte bitkiyi aşırı terlemeden korur."}],"ans":"Kısa süreli savunmalar (ABA ile stoma kapanması, yaprak kıvrılması) ani su açığına hızlı ve geri dönüşümlü tepki verir; uzun süreli yapısal uyumlar (kalın kütikula, gömülü stoma, küçük/tüylü yaprak) kalıcı su tasarrufu sağlar, ikisi birlikte aşırı terlemeden korur."},{"q":"Terleme hızının fotosentez hızıyla genellikle birlikte değişmesini, her ikisinin de stoma açıklığına bağlı olmasıyla açıklayınız.","steps":[{"t":"Ortak kapı","a":"CO2 girişi ve su buharı çıkışı aynı yolu kullanır","d":"Fotosentez için gerekli karbondioksit ve terleme ile kaybedilen su buharı aynı stomalardan geçer. Bu yüzden stoma açıklığı her iki süreci aynı anda denetler."},{"t":"Açıklık artışı","a":"Stoma açılınca ikisi de artar","d":"Stomalar açıldığında hem CO2 girişi artıp fotosentez hızlanır hem de su buharı çıkışı artıp terleme yükselir. İki süreç birlikte yükselme eğilimindedir."},{"t":"Açıklık azalışı","a":"Stoma kapanınca ikisi de azalır","d":"Stomalar kapandığında karbondioksit girişi azalıp fotosentez yavaşlar ve aynı anda terleme de düşer. Yani iki süreç birlikte gerilemektedir."},{"t":"Sonuç","a":"Ortak denetim paralel değişim yaratır","d":"Fotosentez ve terleme aynı stoma kapısına bağlı olduğundan çoğu koşulda paralel (birlikte) değişir. Bitki bu nedenle CO2 kazancı ile su kaybı arasında sürekli bir denge kurmak zorundadır."}],"ans":"CO2 girişi ve su buharı çıkışı aynı stomalardan geçtiğinden stoma açıldığında hem fotosentez hem terleme artar, kapandığında ikisi de azalır; bu ortak denetim iki sürecin paralel değişmesine yol açar."}]}}};
